{
  "name": "ArbNoor",
  "description": "A premium, distraction-free Islamic audio experience. Listen to Naats, Nasheeds, and Duas completely free with offline support and background play."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  NAAT = 'Naat',
  NASHEED = 'Nasheed',
  HAMD = 'Hamd',
  DUA = 'Dua',
  QURAN = 'Quran'
}

export interface Track {
  id: string;
  title: string;
  artist: string;
  category: Category;
  url: string; // Audio source URL
  coverUrl: string;
  duration: number; // in seconds
}

export interface Playlist {
  id: string;
  name: string;
  trackIds: string[];
}

import React, { createContext, useContext, useState, useRef, useEffect, useCallback } from 'react';
import { Track } from '../types';
import { TRACKS } from '../constants';

interface AudioContextType {
  currentTrack: Track | null;
  isPlaying: boolean;
  progress: number; // 0 to 100
  currentTime: number;
  duration: number;
  playTrack: (track: Track) => void;
  togglePlay: () => void;
  playNext: () => void;
  playPrev: () => void;
  seek: (time: number) => void;
  toggleFavorite: (trackId: string) => void;
  favorites: string[];
  sleepTimer: number | null; // minutes remaining
  setSleepTimer: (minutes: number | null) => void;
  isDownloaded: (trackId: string) => boolean;
  toggleDownload: (trackId: string) => void;
}

const AudioContext = createContext<AudioContextType | undefined>(undefined);

export const useAudio = () => {
  const context = useContext(AudioContext);
  if (!context) {
    throw new Error('useAudio must be used within an AudioProvider');
  }
  return context;
};

export const AudioProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [currentTrack, setCurrentTrack] = useState<Track | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [favorites, setFavorites] = useState<string[]>(() => {
    const saved = localStorage.getItem('arbnoor_favorites');
    return saved ? JSON.parse(saved) : [];
  });
  const [downloads, setDownloads] = useState<string[]>(() => {
    const saved = localStorage.getItem('arbnoor_downloads');
    return saved ? JSON.parse(saved) : [];
  });
  const [sleepTimer, setSleepTimerState] = useState<number | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    audioRef.current = new Audio();

    const audio = audioRef.current;

    const updateTime = () => {
      setCurrentTime(audio.currentTime);
      setDuration(audio.duration || 0);
    };

    const handleEnded = () => {
      playNext();
    };

    audio.addEventListener('timeupdate', updateTime);
    audio.addEventListener('loadedmetadata', updateTime);
    audio.addEventListener('ended', handleEnded);

    return () => {
      audio.removeEventListener('timeupdate', updateTime);
      audio.removeEventListener('loadedmetadata', updateTime);
      audio.removeEventListener('ended', handleEnded);
      audio.pause();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Sleep Timer Logic
  useEffect(() => {
    if (sleepTimer !== null) {
      if (sleepTimer <= 0) {
        if (audioRef.current) audioRef.current.pause();
        setIsPlaying(false);
        setSleepTimerState(null);
        return;
      }

      timerRef.current = window.setTimeout(() => {
        setSleepTimerState(prev => (prev ? prev - 1 : null));
      }, 60000); // Check every minute
    }

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [sleepTimer]);

  const setSleepTimer = (minutes: number | null) => {
    setSleepTimerState(minutes);
  };

  const playTrack = (track: Track) => {
    if (audioRef.current) {
      if (currentTrack?.id === track.id) {
        togglePlay();
        return;
      }

      setCurrentTrack(track);
      audioRef.current.src = track.url;
      audioRef.current.play().then(() => {
        setIsPlaying(true);
      }).catch(e => console.error("Playback failed", e));
    }
  };

  const togglePlay = () => {
    if (audioRef.current && currentTrack) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play().catch(e => console.error(e));
        setIsPlaying(true);
      }
    }
  };

  const seek = (time: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const playNext = useCallback(() => {
    if (!currentTrack) return;
    const currentIndex = TRACKS.findIndex(t => t.id === currentTrack.id);
    const nextIndex = (currentIndex + 1) % TRACKS.length;
    playTrack(TRACKS[nextIndex]);
  }, [currentTrack]);

  const playPrev = useCallback(() => {
    if (!currentTrack) return;
    const currentIndex = TRACKS.findIndex(t => t.id === currentTrack.id);
    const prevIndex = (currentIndex - 1 + TRACKS.length) % TRACKS.length;
    playTrack(TRACKS[prevIndex]);
  }, [currentTrack]);

  const toggleFavorite = (trackId: string) => {
    setFavorites(prev => {
      const newFavs = prev.includes(trackId) 
        ? prev.filter(id => id !== trackId)
        : [...prev, trackId];
      localStorage.setItem('arbnoor_favorites', JSON.stringify(newFavs));
      return newFavs;
    });
  };

  const toggleDownload = (trackId: string) => {
    // In a real PWA, this would use CacheStorage or IndexedDB
    setDownloads(prev => {
      const newDownloads = prev.includes(trackId)
        ? prev.filter(id => id !== trackId)
        : [...prev, trackId];
      localStorage.setItem('arbnoor_downloads', JSON.stringify(newDownloads));
      return newDownloads;
    });
  };

  const isDownloaded = (trackId: string) => downloads.includes(trackId);

  const progress = duration ? (currentTime / duration) * 100 : 0;

  return (
    <AudioContext.Provider value={{
      currentTrack,
      isPlaying,
      progress,
      currentTime,
      duration,
      playTrack,
      togglePlay,
      playNext,
      playPrev,
      seek,
      toggleFavorite,
      favorites,
      sleepTimer,
      setSleepTimer,
      isDownloaded,
      toggleDownload
    }}>
      {children}
    </AudioContext.Provider>
  );
};

import React, { useState } from 'react';
import { ChevronDown, Play, Pause, SkipBack, SkipForward, Heart, Moon, Share2, Download, ListMusic } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

interface PlayerOverlayProps {
  isOpen: boolean;
  onClose: () => void;
}

const PlayerOverlay: React.FC<PlayerOverlayProps> = ({ isOpen, onClose }) => {
  const { 
    currentTrack, 
    isPlaying, 
    togglePlay, 
    playNext, 
    playPrev, 
    seek, 
    duration, 
    currentTime,
    favorites,
    toggleFavorite,
    sleepTimer,
    setSleepTimer,
    isDownloaded,
    toggleDownload
  } = useAudio();

  const [showSleepOptions, setShowSleepOptions] = useState(false);

  if (!isOpen || !currentTrack) return null;

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
  };

  const isFav = favorites.includes(currentTrack.id);
  const isDown = isDownloaded(currentTrack.id);

  return (
    <div className="fixed inset-0 z-50 bg-slate-950 flex flex-col transition-transform duration-300 ease-in-out">
      {/* Header */}
      <div className="flex justify-between items-center p-6 mt-2">
        <button onClick={onClose} className="p-2 text-slate-400 hover:text-white transition-colors">
          <ChevronDown size={32} />
        </button>
        <span className="text-xs uppercase tracking-widest text-amber-500 font-semibold">Now Playing</span>
        <button 
          onClick={() => setShowSleepOptions(!showSleepOptions)} 
          className={`p-2 transition-colors ${sleepTimer ? 'text-amber-400' : 'text-slate-400 hover:text-white'}`}
        >
          <Moon size={24} fill={sleepTimer ? "currentColor" : "none"} />
        </button>
      </div>

      {/* Sleep Timer Menu */}
      {showSleepOptions && (
        <div className="absolute top-20 right-6 bg-slate-900 border border-slate-800 rounded-lg shadow-xl p-2 w-48 z-50">
          <p className="text-xs text-slate-500 px-3 py-2 uppercase font-bold">Sleep Timer</p>
          {[15, 30, 45, 60].map((min) => (
            <button
              key={min}
              onClick={() => {
                setSleepTimer(min);
                setShowSleepOptions(false);
              }}
              className="block w-full text-left px-3 py-2 text-sm text-slate-300 hover:bg-slate-800 rounded"
            >
              {min} Minutes
            </button>
          ))}
          <button
            onClick={() => {
              setSleepTimer(null);
              setShowSleepOptions(false);
            }}
            className="block w-full text-left px-3 py-2 text-sm text-red-400 hover:bg-slate-800 rounded"
          >
            Turn Off
          </button>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col items-center justify-center px-8">
        {/* Album Art */}
        <div className="w-full max-w-sm aspect-square bg-slate-900 rounded-2xl shadow-2xl shadow-emerald-900/20 overflow-hidden mb-8 ring-1 ring-slate-800">
          <img 
            src={currentTrack.coverUrl} 
            alt={currentTrack.title} 
            className="w-full h-full object-cover opacity-90"
          />
        </div>

        {/* Track Info */}
        <div className="w-full max-w-sm flex justify-between items-start mb-6">
          <div>
            <h2 className="text-2xl font-bold text-white mb-1 leading-tight">{currentTrack.title}</h2>
            <p className="text-emerald-400 text-lg">{currentTrack.artist}</p>
          </div>
          <button 
            onClick={() => toggleFavorite(currentTrack.id)}
            className={`p-2 rounded-full transition-colors ${isFav ? 'text-red-500' : 'text-slate-400'}`}
          >
            <Heart size={28} fill={isFav ? "currentColor" : "none"} />
          </button>
        </div>

        {/* Progress Bar */}
        <div className="w-full max-w-sm mb-2">
          <input
            type="range"
            min="0"
            max={duration || 100}
            value={currentTime}
            onChange={(e) => seek(Number(e.target.value))}
            className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-amber-500"
          />
          <div className="flex justify-between mt-2 text-xs text-slate-500 font-medium">
            <span>{formatTime(currentTime)}</span>
            <span>{formatTime(duration)}</span>
          </div>
        </div>

        {/* Controls */}
        <div className="w-full max-w-sm flex justify-between items-center mt-6 mb-8">
          <button onClick={playPrev} className="text-slate-300 hover:text-white transition-transform active:scale-95 p-2">
            <SkipBack size={32} />
          </button>

          <button 
            onClick={togglePlay} 
            className="bg-amber-500 text-slate-950 rounded-full p-6 hover:bg-amber-400 transition-transform active:scale-95 shadow-lg shadow-amber-500/20"
          >
            {isPlaying ? <Pause size={36} fill="currentColor" /> : <Play size={36} fill="currentColor" className="ml-1" />}
          </button>

          <button onClick={playNext} className="text-slate-300 hover:text-white transition-transform active:scale-95 p-2">
            <SkipForward size={32} />
          </button>
        </div>

        {/* Action Buttons */}
        <div className="w-full max-w-sm flex justify-around items-center px-4">
          <button 
            onClick={() => toggleDownload(currentTrack.id)}
            className={`flex flex-col items-center gap-1 text-xs font-medium transition-colors ${isDown ? 'text-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}
          >
            <Download size={20} />
            <span>{isDown ? 'Saved' : 'Save'}</span>
          </button>
          <button className="flex flex-col items-center gap-1 text-slate-500 hover:text-slate-300 text-xs font-medium transition-colors">
            <Share2 size={20} />
            <span>Share</span>
          </button>
          <button className="flex flex-col items-center gap-1 text-slate-500 hover:text-slate-300 text-xs font-medium transition-colors">
            <ListMusic size={20} />
            <span>Lyrics</span>
          </button>
        </div>
      </div>

      {/* Bottom Spacer for safe area */}
      <div className="h-8"></div>
    </div>
  );
};

export default PlayerOverlay;

import React, { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { Home, Search, Library, Settings, Play, Pause, X } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import PlayerOverlay from './PlayerOverlay';

const Layout = () => {
  const location = useLocation();
  const { currentTrack, isPlaying, togglePlay, progress } = useAudio();
  const [isFullPlayerOpen, setIsFullPlayerOpen] = useState(false);

  const isActive = (path: string) => location.pathname === path ? 'text-amber-400' : 'text-slate-500';

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col font-sans">
      <main className="flex-1 overflow-y-auto pb-32">
        <Outlet />
      </main>

      {/* Mini Player */}
      {currentTrack && !isFullPlayerOpen && (
        <div 
          onClick={() => setIsFullPlayerOpen(true)}
          className="fixed bottom-16 left-0 right-0 bg-slate-900/95 backdrop-blur-md border-t border-slate-800 px-4 py-2 flex items-center justify-between cursor-pointer z-40 transition-all"
        >
          {/* Progress Indicator Line */}
          <div className="absolute top-0 left-0 h-[2px] bg-emerald-500 transition-all duration-500" style={{ width: `${progress}%` }}></div>

          <div className="flex items-center gap-3 overflow-hidden">
            <img 
              src={currentTrack.coverUrl} 
              alt="cover" 
              className="w-10 h-10 rounded-md object-cover flex-shrink-0" 
            />
            <div className="truncate">
              <h4 className="text-sm font-medium text-white truncate">{currentTrack.title}</h4>
              <p className="text-xs text-slate-400 truncate">{currentTrack.artist}</p>
            </div>
          </div>

          <button 
            onClick={(e) => {
              e.stopPropagation();
              togglePlay();
            }}
            className="p-2 text-white hover:text-amber-400 transition-colors"
          >
            {isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" />}
          </button>
        </div>
      )}

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-slate-950 border-t border-slate-900 py-3 px-6 flex justify-between items-center z-40">
        <Link to="/" className={`flex flex-col items-center gap-1 ${isActive('/')}`}>
          <Home size={22} />
          <span className="text-[10px] font-medium">Home</span>
        </Link>
        <Link to="/search" className={`flex flex-col items-center gap-1 ${isActive('/search')}`}>
          <Search size={22} />
          <span className="text-[10px] font-medium">Search</span>
        </Link>
        <Link to="/library" className={`flex flex-col items-center gap-1 ${isActive('/library')}`}>
          <Library size={22} />
          <span className="text-[10px] font-medium">Library</span>
        </Link>
        <Link to="/settings" className={`flex flex-col items-center gap-1 ${isActive('/settings')}`}>
          <Settings size={22} />
          <span className="text-[10px] font-medium">Settings</span>
        </Link>
      </nav>

      {/* Full Screen Player */}
      <PlayerOverlay 
        isOpen={isFullPlayerOpen} 
        onClose={() => setIsFullPlayerOpen(false)} 
      />
    </div>
  );
};

export default Layout;

import React from 'react';
import { Play } from 'lucide-react';
import { TRACKS, CATEGORIES } from '../constants';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

const Home = () => {
  const { playTrack, currentTrack, isPlaying } = useAudio();
  const featured = TRACKS[0]; // Just picking first as featured

  return (
    <div className="p-5 space-y-8">
      {/* Header */}
      <div className="flex justify-between items-center mt-2">
        <div>
          <h1 className="text-xl font-bold text-emerald-500 tracking-wide">ArbNoor</h1>
          <p className="text-xs text-slate-400">Peaceful Islamic Audio</p>
        </div>
        <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-slate-950 font-bold text-xs">
          A
        </div>
      </div>

      {/* Featured Card */}
      <div className="relative w-full aspect-[2/1] bg-gradient-to-br from-emerald-900 to-slate-900 rounded-2xl overflow-hidden shadow-lg group cursor-pointer" onClick={() => playTrack(featured)}>
        <img src={featured.coverUrl} alt="featured" className="absolute inset-0 w-full h-full object-cover mix-blend-overlay opacity-60 group-hover:scale-105 transition-transform duration-500" />
        <div className="absolute inset-0 p-5 flex flex-col justify-end">
          <span className="inline-block px-2 py-1 bg-amber-500/20 text-amber-400 text-[10px] font-bold uppercase tracking-wider rounded w-fit mb-2 border border-amber-500/30">
            Featured Naat
          </span>
          <h2 className="text-xl font-bold text-white mb-1">{featured.title}</h2>
          <p className="text-sm text-slate-300">{featured.artist}</p>

          <button className="absolute bottom-5 right-5 w-12 h-12 bg-amber-500 rounded-full flex items-center justify-center shadow-lg shadow-amber-500/30 transition-transform active:scale-90">
             {(currentTrack?.id === featured.id && isPlaying) ? <span className="w-3 h-3 bg-slate-900 animate-pulse"></span> : <Play fill="#0f172a" className="ml-1 text-slate-900" size={20} />}
          </button>
        </div>
      </div>

      {/* Categories */}
      <div>
        <h3 className="text-lg font-bold text-white mb-4">Categories</h3>
        <div className="grid grid-cols-2 gap-3">
          {CATEGORIES.map((cat) => (
            <div key={cat.id} className={`h-24 rounded-xl bg-gradient-to-br ${cat.color} p-4 relative overflow-hidden flex items-end shadow-md`}>
              <span className="text-white font-bold relative z-10">{cat.label}</span>
              <div className="absolute -top-4 -right-4 w-20 h-20 bg-white/10 rounded-full blur-xl"></div>
            </div>
          ))}
        </div>
      </div>

      {/* Recent / Recommended */}
      <div>
        <h3 className="text-lg font-bold text-white mb-4">For You</h3>
        <div className="space-y-4">
          {TRACKS.slice(1).map((track) => (
            <TrackRow key={track.id} track={track} />
          ))}
        </div>
      </div>
    </div>
  );
};

const TrackRow = ({ track }: { track: Track }) => {
  const { playTrack, currentTrack, isPlaying } = useAudio();
  const isActive = currentTrack?.id === track.id;

  return (
    <div 
      onClick={() => playTrack(track)}
      className={`flex items-center gap-4 p-3 rounded-xl transition-colors cursor-pointer ${isActive ? 'bg-slate-800 border border-emerald-500/30' : 'hover:bg-slate-900'}`}
    >
      <div className="relative w-12 h-12 rounded-lg overflow-hidden flex-shrink-0">
        <img src={track.coverUrl} alt={track.title} className="w-full h-full object-cover" />
        {isActive && isPlaying && (
          <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
            <div className="flex gap-0.5 items-end h-3">
              <div className="w-1 bg-amber-400 animate-[bounce_1s_infinite] h-2"></div>
              <div className="w-1 bg-amber-400 animate-[bounce_1.2s_infinite] h-full"></div>
              <div className="w-1 bg-amber-400 animate-[bounce_0.8s_infinite] h-1.5"></div>
            </div>
          </div>
        )}
      </div>
      <div className="flex-1 min-w-0">
        <h4 className={`text-sm font-semibold truncate ${isActive ? 'text-amber-400' : 'text-slate-100'}`}>
          {track.title}
        </h4>
        <p className="text-xs text-slate-400 truncate">{track.artist}</p>
      </div>
      <div className="text-xs text-slate-600 font-medium">
        {Math.floor(track.duration / 60)}:{Math.floor(track.duration % 60).toString().padStart(2, '0')}
      </div>
    </div>
  );
};

export default Home;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, XCircle } from 'lucide-react';
import { TRACKS } from '../constants';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

const Search = () => {
  const [query, setQuery] = useState('');
  const { playTrack, currentTrack } = useAudio();

  const filteredTracks = useMemo(() => {
    if (!query) return [];
    return TRACKS.filter(t => 
      t.title.toLowerCase().includes(query.toLowerCase()) || 
      t.artist.toLowerCase().includes(query.toLowerCase())
    );
  }, [query]);

  return (
    <div className="p-5 min-h-full">
      <h1 className="text-2xl font-bold mb-6 text-white">Search</h1>

      {/* Search Bar */}
      <div className="relative mb-6">
        <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search Naat, Reciter, Nasheed..."
          className="w-full bg-slate-900 border border-slate-800 text-white pl-12 pr-10 py-4 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all placeholder:text-slate-600"
        />
        {query && (
          <button 
            onClick={() => setQuery('')}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500"
          >
            <XCircle size={18} fill="currentColor" className="text-slate-700" />
          </button>
        )}
      </div>

      {/* Results or Empty State */}
      <div className="space-y-4">
        {query.length > 0 ? (
          filteredTracks.length > 0 ? (
            filteredTracks.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))
          ) : (
            <div className="text-center py-10 text-slate-500">
              <p>No results found for "{query}"</p>
            </div>
          )
        ) : (
          <div>
            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Browse All</h3>
            {TRACKS.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const SearchItem = ({ track, onClick, active }: { track: Track, onClick: () => void, active: boolean }) => (
  <div onClick={onClick} className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer ${active ? 'bg-emerald-900/20' : ''}`}>
    <img src={track.coverUrl} className="w-12 h-12 rounded bg-slate-800 object-cover" alt="" />
    <div className="flex-1 border-b border-slate-900 pb-2">
      <h4 className={`text-sm font-medium ${active ? 'text-emerald-400' : 'text-slate-200'}`}>{track.title}</h4>
      <p className="text-xs text-slate-500">{track.artist}</p>
    </div>
  </div>
);

export default Search;

import React, { useState } from 'react';
import { TRACKS } from '../constants';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music } from 'lucide-react';

type Tab = 'favorites' | 'downloads';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const { favorites, isDownloaded, playTrack, currentTrack } = useAudio();

