  const featured = tracks.length > 0 ? tracks[0] : null;

  return (
    <div className="p-5 space-y-8">
      {/* Header */}
      <div className="flex justify-between items-center mt-2">
        <div>
          <h1 className="text-xl font-bold text-emerald-500 tracking-wide">ArbNoor</h1>
          <p className="text-xs text-emerald-400/80 flex items-center gap-1 font-medium">
            <ShieldCheck size={12} />
            100% Vocals Only • Music Free
          </p>
        </div>
        <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-slate-950 font-bold text-xs">
          A
        </div>
      </div>

      {/* Featured Card */}
      {featured && (
        <div className="relative w-full aspect-[2/1] bg-gradient-to-br from-emerald-900 to-slate-900 rounded-2xl overflow-hidden shadow-lg group cursor-pointer" onClick={() => playTrack(featured)}>
          <img src={featured.coverUrl} alt="featured" className="absolute inset-0 w-full h-full object-cover mix-blend-overlay opacity-60 group-hover:scale-105 transition-transform duration-500" />
