            <div className="flex gap-2 mb-2">
              <span className="inline-block px-2 py-1 bg-amber-500/20 text-amber-400 text-[10px] font-bold uppercase tracking-wider rounded border border-amber-500/30">
                Featured {featured.category}
              </span>
              <span className="inline-flex items-center gap-1 px-2 py-1 bg-emerald-500/20 text-emerald-400 text-[10px] font-bold uppercase tracking-wider rounded border border-emerald-500/30">
                <Mic size={10} /> Vocals Only
              </span>
            </div>
            <h2 className="text-xl font-bold text-white mb-1">{featured.title}</h2>
            <p className="text-sm text-slate-300">{featured.artist}</p>

            <button className="absolute bottom-5 right-5 w-12 h-12 bg-amber-500 rounded-full flex items-center justify-center shadow-lg shadow-amber-500/30 transition-transform active:scale-90">
               {(currentTrack?.id === featured.id && isPlaying) ? <span className="w-3 h-3 bg-slate-900 animate-pulse"></span> : <Play fill="#0f172a" className="ml-1 text-slate-900" size={20} />}
