  );
};

const TrackRow = ({ track }: { track: Track }) => {
  const { playTrack, currentTrack, isPlaying } = useAudio();
  const isActive = currentTrack?.id === track.id;

  return (
    <div 
      onClick={() => playTrack(track)}
      className={`flex items-center gap-4 p-3 rounded-xl transition-colors cursor-pointer ${isActive ? 'bg-slate-800 border border-emerald-500/30' : 'hover:bg-slate-900'}`}
    >
      <div className="relative w-12 h-12 rounded-lg overflow-hidden flex-shrink-0">
        <img src={track.coverUrl} alt={track.title} className="w-full h-full object-cover" />
        {isActive && isPlaying && (
          <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
            <div className="flex gap-0.5 items-end h-3">
              <div className="w-1 bg-amber-400 animate-[bounce_1s_infinite] h-2"></div>
              <div className="w-1 bg-amber-400 animate-[bounce_1.2s_infinite] h-full"></div>
              <div className="w-1 bg-amber-400 animate-[bounce_0.8s_infinite] h-1.5"></div>
            </div>
          </div>
        )}
      </div>
      <div className="flex-1 min-w-0">
        <h4 className={`text-sm font-semibold truncate ${isActive ? 'text-amber-400' : 'text-slate-100'}`}>
          {track.title}
        </h4>
        <p className="text-xs text-slate-400 truncate">{track.artist}</p>
      </div>
      <div className="flex flex-col items-end gap-1">
        <div className="text-xs text-slate-600 font-medium">
          {Math.floor(track.duration / 60)}:{Math.floor(track.duration % 60).toString().padStart(2, '0')}
        </div>
        {track.isVocalsOnly && (
           <span className="text-[9px] text-emerald-500/70 border border-emerald-500/20 px-1 rounded flex items-center gap-0.5">
             <ShieldCheck size={8} /> Vocals
           </span>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, XCircle } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

const Search = () => {
  const [query, setQuery] = useState('');
  const { playTrack, currentTrack, tracks } = useAudio();

  const filteredTracks = useMemo(() => {
    if (!query) return [];
    return tracks.filter(t => 
      t.title.toLowerCase().includes(query.toLowerCase()) || 
      t.artist.toLowerCase().includes(query.toLowerCase())
    );
  }, [query, tracks]);

  return (
    <div className="p-5 min-h-full">
      <h1 className="text-2xl font-bold mb-6 text-white">Search</h1>

      {/* Search Bar */}
      <div className="relative mb-6">
        <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
        <input 
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search Naat, Reciter, Nasheed..."
          className="w-full bg-slate-900 border border-slate-800 text-white pl-12 pr-10 py-4 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500/50 transition-all placeholder:text-slate-600"
        />
        {query && (
          <button 
            onClick={() => setQuery('')}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500"
          >
            <XCircle size={18} fill="currentColor" className="text-slate-700" />
          </button>
        )}
      </div>

      {/* Results or Empty State */}
      <div className="space-y-4">
        {query.length > 0 ? (
          filteredTracks.length > 0 ? (
            filteredTracks.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))
          ) : (
            <div className="text-center py-10 text-slate-500">
              <p>No results found for "{query}"</p>
            </div>
          )
        ) : (
          <div>
            <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Browse All</h3>
            {tracks.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

const SearchItem = ({ track, onClick, active }: { track: Track, onClick: () => void, active: boolean }) => (
  <div onClick={onClick} className={`flex items-center gap-3 p-2 rounded-lg cursor-pointer ${active ? 'bg-emerald-900/20' : ''}`}>
    <img src={track.coverUrl} className="w-12 h-12 rounded bg-slate-800 object-cover" alt="" />
    <div className="flex-1 border-b border-slate-900 pb-2">
      <h4 className={`text-sm font-medium ${active ? 'text-emerald-400' : 'text-slate-200'}`}>{track.title}</h4>
      <p className="text-xs text-slate-500">{track.artist}</p>
    </div>
  </div>
);

export default Search;

import React, { useState } from 'react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music } from 'lucide-react';

type Tab = 'favorites' | 'downloads';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const { favorites, isDownloaded, playTrack, currentTrack, tracks } = useAudio();

  const favoriteTracks = tracks.filter(t => favorites.includes(t.id));
  const downloadedTracks = tracks.filter(t => isDownloaded(t.id));

  const displayTracks = activeTab === 'favorites' ? favoriteTracks : downloadedTracks;

  return (
    <div className="p-5 min-h-full">
      <h1 className="text-2xl font-bold mb-6 text-white">Your Library</h1>

      {/* Tabs */}
      <div className="flex gap-4 border-b border-slate-800 mb-6">
        <button 
          onClick={() => setActiveTab('favorites')}
          className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'favorites' ? 'text-emerald-400' : 'text-slate-500'}`}
        >
          Favorites
          {activeTab === 'favorites' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-emerald-400 rounded-t-full"></div>}
        </button>
        <button 
          onClick={() => setActiveTab('downloads')}
          className={`pb-3 text-sm font-medium transition-colors relative ${activeTab === 'downloads' ? 'text-emerald-400' : 'text-slate-500'}`}
        >
          Downloads
          {activeTab === 'downloads' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-emerald-400 rounded-t-full"></div>}
        </button>
      </div>

      {/* Content */}
      <div className="space-y-2">
        {displayTracks.length > 0 ? (
          displayTracks.map(track => (
            <LibraryItem key={track.id} track={track} onClick={() => playTrack(track)} isActive={currentTrack?.id === track.id} />
          ))
        ) : (
          <EmptyState type={activeTab} />
        )}
      </div>
    </div>
  );
};

const LibraryItem = ({ track, onClick, isActive }: { track: Track, onClick: () => void, isActive: boolean }) => (
  <div 
    onClick={onClick}
    className={`flex items-center gap-4 p-3 rounded-xl transition-colors cursor-pointer ${isActive ? 'bg-slate-800' : 'hover:bg-slate-900'}`}
  >
    <div className="w-10 h-10 rounded overflow-hidden bg-slate-800">
      <img src={track.coverUrl} alt="" className="w-full h-full object-cover" />
    </div>
    <div className="flex-1">
      <h4 className={`text-sm font-semibold ${isActive ? 'text-emerald-400' : 'text-slate-200'}`}>{track.title}</h4>
      <p className="text-xs text-slate-500">{track.artist}</p>
    </div>
    {isActive && <Music size={16} className="text-emerald-500" />}
  </div>
);

const EmptyState = ({ type }: { type: Tab }) => (
  <div className="flex flex-col items-center justify-center py-20 text-slate-600">
    <div className="w-16 h-16 rounded-full bg-slate-900 flex items-center justify-center mb-4">
      {type === 'favorites' ? <Heart size={32} /> : <Download size={32} />}
    </div>
    <p className="text-sm font-medium">No {type} yet</p>
    <p className="text-xs mt-1">Start listening to add to your library.</p>
  </div>
);

export default Library;

import React, { useState } from 'react';
