        <p className="text-center text-xs text-slate-600 mt-8">
          Authorized personnel only. All attempts are logged.
        </p>
      </div>
    </div>
  );
};

export default AdminLogin;

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAudio } from '../context/AudioContext';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Plus, Trash2, LogOut, Play, Square, CheckCircle, AlertTriangle } from 'lucide-react';
import { Category, Track } from '../types';

const AdminDashboard = () => {
  const { logout } = useAuth();
  const { tracks, addTrack, deleteTrack } = useAudio();
  const navigate = useNavigate();

  // Form State
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [category, setCategory] = useState<Category>(Category.NAAT);
  const [url, setUrl] = useState('');
  const [coverUrl, setCoverUrl] = useState('https://picsum.photos/400/400');
  const [isVocalsVerified, setIsVocalsVerified] = useState(false);
  const [previewAudio, setPreviewAudio] = useState<HTMLAudioElement | null>(null);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);

  const handleLogout = () => {
    if (previewAudio) {
      previewAudio.pause();
    }
    logout();
    navigate('/admin/login');
  };

  const handlePreview = () => {
    if (isPreviewPlaying && previewAudio) {
      previewAudio.pause();
      setIsPreviewPlaying(false);
    } else {
      if (!url) return;
      const audio = new Audio(url);
      audio.onended = () => setIsPreviewPlaying(false);
      audio.play().catch(e => alert("Could not play audio url. Check link."));
      setPreviewAudio(audio);
      setIsPreviewPlaying(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isVocalsVerified) {
      alert("You must verify that the content is Vocals Only.");
      return;
    }

    const newTrack: Track = {
      id: Date.now().toString(),
      title,
      artist,
      category,
      url,
      coverUrl,
      duration: 0, // In a real app, we'd extract metadata
      isVocalsOnly: true
    };

    addTrack(newTrack);
    // Reset form
    setTitle('');
    setArtist('');
    setUrl('');
    setIsVocalsVerified(false);
    alert("Track published successfully!");
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200">
      {/* Navbar */}
      <div className="bg-slate-900 border-b border-slate-800 p-4 flex justify-between items-center sticky top-0 z-10">
        <div className="flex items-center gap-2">
          <ShieldCheck className="text-emerald-500" />
          <h1 className="font-bold text-white">ArbNoor Admin</h1>
        </div>
        <button onClick={handleLogout} className="text-xs font-bold text-red-400 hover:text-red-300 flex items-center gap-1">
          <LogOut size={14} /> Logout
        </button>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Upload Form */}
        <div className="lg:col-span-1">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 shadow-xl">
            <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
              <Plus size={20} className="text-amber-500" /> Upload Content
            </h2>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Title</label>
                <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm focus:border-emerald-500 outline-none" placeholder="e.g. Maula Ya Salli" />
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Reciter / Artist</label>
                <input required value={artist} onChange={e => setArtist(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm focus:border-emerald-500 outline-none" placeholder="e.g. Junaid Jamshed" />
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Category</label>
                <select value={category} onChange={e => setCategory(e.target.value as Category)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm focus:border-emerald-500 outline-none">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Audio URL</label>
                <div className="flex gap-2">
                  <input required value={url} onChange={e => setUrl(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm focus:border-emerald-500 outline-none" placeholder="https://..." />
                  <button type="button" onClick={handlePreview} className="bg-slate-800 p-3 rounded-lg hover:bg-slate-700">
                    {isPreviewPlaying ? <Square size={18} className="text-red-400" /> : <Play size={18} className="text-emerald-400" />}
                  </button>
                </div>
              </div>

              <div className="bg-emerald-900/20 border border-emerald-500/20 rounded-lg p-4">
                <label className="flex items-start gap-3 cursor-pointer">
                  <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center flex-shrink-0 ${isVocalsVerified ? 'bg-emerald-500 border-emerald-500' : 'border-slate-600'}`}>
                    {isVocalsVerified && <CheckCircle size={14} className="text-white" />}
                  </div>
                  <input type="checkbox" className="hidden" checked={isVocalsVerified} onChange={e => setIsVocalsVerified(e.target.checked)} />
                  <div className="text-xs text-slate-300">
                    <span className="font-bold text-emerald-400 block mb-1">Vocals Only Verification</span>
                    I certify that this audio file does NOT contain any musical instruments, beats, or non-compliant background music.
                  </div>
                </label>
              </div>

              <button type="submit" className="w-full bg-amber-500 hover:bg-amber-400 text-slate-900 font-bold py-3 rounded-xl transition-colors">
                Publish Track
              </button>
            </form>
          </div>
        </div>

        {/* Manage Content List */}
        <div className="lg:col-span-2">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden shadow-xl">
             <div className="p-6 border-b border-slate-800">
                <h2 className="text-lg font-bold text-white">Manage Content</h2>
             </div>
             <div className="divide-y divide-slate-800 max-h-[600px] overflow-y-auto">
                {tracks.map(track => (
                  <div key={track.id} className="p-4 flex items-center gap-4 hover:bg-slate-800/50 transition-colors">
                    <img src={track.coverUrl} className="w-10 h-10 rounded bg-slate-800 object-cover" alt="" />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <h4 className="text-sm font-semibold text-white truncate">{track.title}</h4>
                        <span className="text-[10px] bg-slate-800 px-2 py-0.5 rounded text-slate-400 border border-slate-700">{track.category}</span>
                      </div>
                      <p className="text-xs text-slate-500">{track.artist}</p>
                    </div>
                    <button 
                      onClick={() => deleteTrack(track.id)}
                      className="p-2 text-slate-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"
                      title="Delete Content"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                ))}
             </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;

import React from 'react';
import { HashRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import Layout from './components/Layout';
import Home from './pages/Home';
import Search from './pages/Search';
import Library from './pages/Library';
import Settings from './pages/Settings';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import { AudioProvider } from './context/AudioContext';
import { AuthProvider, useAuth } from './context/AuthContext';

// Protected Route Component
const ProtectedRoute = () => {
  const { isAdmin } = useAuth();
  return isAdmin ? <Outlet /> : <Navigate to="/admin/login" replace />;
};

const App = () => {
  return (
    <AuthProvider>
      <AudioProvider>
        <HashRouter>
          <Routes>
            {/* User Routes */}
            <Route path="/" element={<Layout />}>
              <Route index element={<Home />} />
              <Route path="search" element={<Search />} />
              <Route path="library" element={<Library />} />
              <Route path="settings" element={<Settings />} />
            </Route>

            {/* Admin Routes */}
            <Route path="/admin/login" element={<AdminLogin />} />
            <Route element={<ProtectedRoute />}>
              <Route path="/admin/dashboard" element={<AdminDashboard />} />
            </Route>

            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </HashRouter>
      </AudioProvider>
    </AuthProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { Home, Search, Library, Settings, Play, Pause, X } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import PlayerOverlay from './PlayerOverlay';

const Layout = () => {
  const location = useLocation();
  const { currentTrack, isPlaying, togglePlay, progress } = useAudio();
  const [isFullPlayerOpen, setIsFullPlayerOpen] = useState(false);

  const isActive = (path: string) => location.pathname === path ? 'text-teal-700' : 'text-stone-400';

  return (
    <div className="min-h-screen text-stone-800 flex flex-col font-sans">
      <main className="flex-1 overflow-y-auto pb-32">
        <Outlet />
      </main>

      {/* Mini Player - Glass Card */}
      {currentTrack && !isFullPlayerOpen && (
        <div 
          onClick={() => setIsFullPlayerOpen(true)}
          className="fixed bottom-20 left-4 right-4 bg-white/70 backdrop-blur-xl border border-white/40 shadow-xl shadow-stone-200/50 rounded-2xl px-4 py-3 flex items-center justify-between cursor-pointer z-40 transition-all"
        >
          {/* Progress Indicator Line (Subtle) */}
          <div className="absolute bottom-0 left-4 right-4 h-[2px] bg-stone-100 rounded-full overflow-hidden">
             <div className="h-full bg-teal-600/50 transition-all duration-500" style={{ width: `${progress}%` }}></div>
          </div>

          <div className="flex items-center gap-3 overflow-hidden">
            <img 
              src={currentTrack.coverUrl} 
              alt="cover" 
              className="w-10 h-10 rounded-xl object-cover flex-shrink-0 shadow-sm" 
            />
            <div className="truncate">
              <h4 className="text-sm font-bold text-stone-800 truncate">{currentTrack.title}</h4>
              <p className="text-[10px] text-stone-500 truncate uppercase tracking-wider">{currentTrack.artist}</p>
            </div>
          </div>

          <button 
            onClick={(e) => {
              e.stopPropagation();
              togglePlay();
            }}
            className="w-10 h-10 rounded-full bg-teal-700/10 flex items-center justify-center text-teal-800 hover:bg-teal-700/20 transition-colors"
          >
            {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-0.5" />}
          </button>
        </div>
      )}

      {/* Bottom Navigation - Glass Bar */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-xl border-t border-white/50 py-4 px-6 flex justify-between items-center z-40 shadow-[0_-4px_20px_rgba(0,0,0,0.02)]">
        <Link to="/" className={`flex flex-col items-center gap-1 transition-colors ${isActive('/')}`}>
          <Home size={22} strokeWidth={isActive('/') ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Home</span>
        </Link>
        <Link to="/search" className={`flex flex-col items-center gap-1 transition-colors ${isActive('/search')}`}>
          <Search size={22} strokeWidth={isActive('/search') ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Search</span>
        </Link>
        <Link to="/library" className={`flex flex-col items-center gap-1 transition-colors ${isActive('/library')}`}>
          <Library size={22} strokeWidth={isActive('/library') ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Library</span>
        </Link>
        <Link to="/settings" className={`flex flex-col items-center gap-1 transition-colors ${isActive('/settings')}`}>
          <Settings size={22} strokeWidth={isActive('/settings') ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Settings</span>
        </Link>
      </nav>

      {/* Full Screen Player */}
      <PlayerOverlay 
        isOpen={isFullPlayerOpen} 
        onClose={() => setIsFullPlayerOpen(false)} 
      />
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { ChevronDown, Play, Pause, SkipBack, SkipForward, Heart, Moon, Share2, Download, ListMusic, ShieldCheck } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

interface PlayerOverlayProps {
  isOpen: boolean;
  onClose: () => void;
}

const PlayerOverlay: React.FC<PlayerOverlayProps> = ({ isOpen, onClose }) => {
  const { 
    currentTrack, 
    isPlaying, 
    togglePlay, 
    playNext, 
    playPrev, 
    seek, 
    duration, 
    currentTime,
    favorites,
    toggleFavorite,
    sleepTimer,
    setSleepTimer,
    isDownloaded,
    toggleDownload
  } = useAudio();

  const [showSleepOptions, setShowSleepOptions] = useState(false);

  if (!isOpen || !currentTrack) return null;

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
  };

  const isFav = favorites.includes(currentTrack.id);
  const isDown = isDownloaded(currentTrack.id);

  return (
    <div className="fixed inset-0 z-50 flex flex-col transition-transform duration-300 ease-in-out bg-[#FDFBF7]/90 backdrop-blur-3xl">
      {/* Background Ambience Blob */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[300px] h-[300px] bg-teal-500/10 rounded-full blur-[100px] pointer-events-none"></div>

      {/* Header */}
      <div className="relative flex justify-between items-center p-6 mt-4 z-10">
        <button onClick={onClose} className="p-2 text-stone-500 hover:text-stone-800 transition-colors bg-white/50 rounded-full">
          <ChevronDown size={28} />
        </button>
        <div className="flex flex-col items-center">
          <span className="text-xs uppercase tracking-widest text-teal-700 font-bold bg-teal-50 px-3 py-1 rounded-full border border-teal-100">Now Playing</span>
        </div>
        <button 
          onClick={() => setShowSleepOptions(!showSleepOptions)} 
          className={`p-2 rounded-full transition-colors ${sleepTimer ? 'text-amber-600 bg-amber-50' : 'text-stone-400 hover:text-stone-800 bg-white/50'}`}
        >
          <Moon size={24} fill={sleepTimer ? "currentColor" : "none"} />
        </button>
      </div>

      {/* Sleep Timer Menu */}
      {showSleepOptions && (
        <div className="absolute top-24 right-6 bg-white/90 backdrop-blur-xl border border-white/50 rounded-2xl shadow-xl shadow-stone-200/50 p-2 w-48 z-50">
          <p className="text-xs text-stone-400 px-3 py-2 uppercase font-bold tracking-wider">Sleep Timer</p>
          {[15, 30, 45, 60].map((min) => (
            <button
              key={min}
              onClick={() => {
                setSleepTimer(min);
                setShowSleepOptions(false);
              }}
              className="block w-full text-left px-3 py-2 text-sm text-stone-700 hover:bg-stone-100 rounded-xl"
            >
              {min} Minutes
            </button>
          ))}
          <button
            onClick={() => {
              setSleepTimer(null);
              setShowSleepOptions(false);
            }}
            className="block w-full text-left px-3 py-2 text-sm text-red-500 hover:bg-red-50 rounded-xl"
          >
            Turn Off
          </button>
        </div>
      )}

      {/* Main Content */}
      <div className="relative flex-1 flex flex-col items-center justify-center px-8 z-10">
        {/* Album Art Card */}
        <div className="w-full max-w-xs aspect-square bg-white rounded-[2rem] shadow-[0_20px_40px_-12px_rgba(0,0,0,0.1)] p-3 mb-10 border border-white/60">
          <div className="w-full h-full rounded-[1.5rem] overflow-hidden relative">
            <img 
              src={currentTrack.coverUrl} 
              alt={currentTrack.title} 
              className="w-full h-full object-cover"
            />
            {currentTrack.isVocalsOnly && (
               <div className="absolute bottom-3 left-0 right-0 flex justify-center">
                 <span className="bg-white/80 backdrop-blur-md text-teal-800 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5 shadow-sm border border-white/50">
                   <ShieldCheck size={12} className="text-teal-600" />
                   Vocals Only
                 </span>
               </div>
            )}
          </div>
        </div>

        {/* Track Info */}
        <div className="w-full max-w-sm flex justify-between items-start mb-8 px-2">
          <div>
            <h2 className="text-2xl font-bold text-stone-900 mb-1 leading-tight">{currentTrack.title}</h2>
            <p className="text-teal-700 text-lg">{currentTrack.artist}</p>
          </div>
          <button 
            onClick={() => toggleFavorite(currentTrack.id)}
            className={`p-3 rounded-full transition-all shadow-sm ${isFav ? 'bg-red-50 text-red-500 shadow-red-100' : 'bg-white text-stone-300 hover:text-stone-500'}`}
          >
            <Heart size={24} fill={isFav ? "currentColor" : "none"} />
          </button>
        </div>

        {/* Progress Bar */}
        <div className="w-full max-w-sm mb-4 px-2">
          <input
            type="range"
            min="0"
            max={duration || 100}
            value={currentTime}
            onChange={(e) => seek(Number(e.target.value))}
            className="w-full h-1.5 bg-stone-200 rounded-lg appearance-none cursor-pointer accent-teal-700"
          />
          <div className="flex justify-between mt-2 text-xs text-stone-400 font-medium font-mono">
            <span>{formatTime(currentTime)}</span>
            <span>{formatTime(duration)}</span>
          </div>
        </div>

        {/* Controls */}
        <div className="w-full max-w-sm flex justify-between items-center mt-4 mb-10 px-4">
          <button onClick={playPrev} className="text-stone-400 hover:text-stone-800 transition-transform active:scale-95 p-2">
            <SkipBack size={32} />
          </button>

          <button 
            onClick={togglePlay} 
            className="bg-stone-900 text-[#FDFBF7] rounded-[2rem] p-7 hover:bg-stone-800 transition-transform active:scale-95 shadow-xl shadow-stone-900/20"
          >
            {isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
          </button>

          <button onClick={playNext} className="text-stone-400 hover:text-stone-800 transition-transform active:scale-95 p-2">
            <SkipForward size={32} />
          </button>
        </div>

        {/* Action Buttons */}
        <div className="w-full max-w-sm flex justify-around items-center px-4">
          <button 
            onClick={() => toggleDownload(currentTrack.id)}
            className={`flex flex-col items-center gap-1 text-xs font-medium transition-colors ${isDown ? 'text-teal-600' : 'text-stone-400 hover:text-stone-600'}`}
          >
            <Download size={20} />
            <span>{isDown ? 'Saved' : 'Save'}</span>
          </button>
          <button className="flex flex-col items-center gap-1 text-stone-400 hover:text-stone-600 text-xs font-medium transition-colors">
            <Share2 size={20} />
            <span>Share</span>
          </button>
          <button className="flex flex-col items-center gap-1 text-stone-400 hover:text-stone-600 text-xs font-medium transition-colors">
            <ListMusic size={20} />
            <span>Lyrics</span>
          </button>
        </div>
      </div>

      {/* Bottom Spacer for safe area */}
      <div className="h-8"></div>
    </div>
  );
};

export default PlayerOverlay;

