              <span className="inline-flex items-center gap-1 px-2.5 py-1 bg-teal-600/90 backdrop-blur-sm text-white text-[10px] font-bold uppercase tracking-wider rounded-lg shadow-sm">
                <Mic size={10} /> Vocals
