const TrackRow = ({ track }: { track: Track }) => {
  const { playTrack, currentTrack, isPlaying } = useAudio();
  const isActive = currentTrack?.id === track.id;

  return (
    <div 
      onClick={() => playTrack(track)}
      className={`flex items-center gap-4 p-3 rounded-2xl transition-all cursor-pointer border ${isActive ? 'bg-white shadow-md border-teal-100' : 'bg-white/40 hover:bg-white border-transparent hover:border-white/60 hover:shadow-sm'}`}
    >
      <div className="relative w-14 h-14 rounded-xl overflow-hidden flex-shrink-0 shadow-sm">
        <img src={track.coverUrl} alt={track.title} className="w-full h-full object-cover" />
        {isActive && isPlaying && (
          <div className="absolute inset-0 bg-stone-900/40 flex items-center justify-center backdrop-blur-[1px]">
            <div className="flex gap-0.5 items-end h-3">
              <div className="w-1 bg-white animate-[bounce_1s_infinite] h-2"></div>
              <div className="w-1 bg-white animate-[bounce_1.2s_infinite] h-full"></div>
              <div className="w-1 bg-white animate-[bounce_0.8s_infinite] h-1.5"></div>
            </div>
          </div>
        )}
      </div>
      <div className="flex-1 min-w-0">
        <h4 className={`text-sm font-bold truncate ${isActive ? 'text-teal-800' : 'text-stone-800'}`}>
          {track.title}
        </h4>
        <p className="text-xs text-stone-500 truncate mt-0.5">{track.artist}</p>
      </div>
      <div className="flex flex-col items-end gap-1.5">
        <div className="text-xs text-stone-400 font-medium font-mono">
          {Math.floor(track.duration / 60)}:{Math.floor(track.duration % 60).toString().padStart(2, '0')}
        </div>
        {track.isVocalsOnly && (
           <span className="text-[8px] text-teal-600 bg-teal-50 border border-teal-100 px-1.5 py-0.5 rounded-md flex items-center gap-0.5 font-bold uppercase tracking-wider">
             <ShieldCheck size={8} /> Vocals
           </span>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, XCircle, Mic } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

const Search = () => {
  const [query, setQuery] = useState('');
  const { playTrack, currentTrack, tracks } = useAudio();

  const filteredTracks = useMemo(() => {
    if (!query) return [];
    return tracks.filter(t => 
      t.title.toLowerCase().includes(query.toLowerCase()) || 
      t.artist.toLowerCase().includes(query.toLowerCase())
    );
  }, [query, tracks]);

  return (
    <div className="p-6 min-h-full">
      <h1 className="text-2xl font-bold mb-6 text-stone-900 font-serif">Search</h1>

      {/* Search Bar */}
      <div className="relative mb-8">
        <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-stone-400" size={20} />
        <input 
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Naat, Reciter, Nasheed..."
          className="w-full bg-white border border-stone-200 text-stone-800 pl-12 pr-10 py-4 rounded-2xl focus:outline-none focus:ring-2 focus:ring-teal-500/20 focus:border-teal-500 transition-all placeholder:text-stone-400 shadow-sm"
        />
        {query && (
          <button 
            onClick={() => setQuery('')}
            className="absolute right-4 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600"
          >
            <XCircle size={18} fill="currentColor" className="text-stone-200" />
          </button>
        )}
      </div>

      {/* Results or Empty State */}
      <div className="space-y-3">
        {query.length > 0 ? (
          filteredTracks.length > 0 ? (
            filteredTracks.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))
          ) : (
            <div className="text-center py-10 text-stone-400">
              <p>No results found for "{query}"</p>
            </div>
          )
        ) : (
          <div>
            <h3 className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-4 px-2">Browse All Content</h3>
            <div className="bg-white/50 backdrop-blur-md rounded-3xl p-2 border border-white/60">
              {tracks.map(track => (
                <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const SearchItem = ({ track, onClick, active }: { track: Track, onClick: () => void, active: boolean }) => (
  <div onClick={onClick} className={`flex items-center gap-3 p-3 rounded-2xl cursor-pointer transition-all ${active ? 'bg-white shadow-sm ring-1 ring-teal-100' : 'hover:bg-white/60'}`}>
    <img src={track.coverUrl} className="w-12 h-12 rounded-xl bg-stone-100 object-cover" alt="" />
    <div className="flex-1 border-b border-stone-100/50 pb-2 mb-1 last:border-0 last:pb-0 last:mb-0">
      <h4 className={`text-sm font-bold ${active ? 'text-teal-800' : 'text-stone-800'}`}>{track.title}</h4>
      <p className="text-xs text-stone-500 flex items-center gap-1">
        {track.artist}
        {track.isVocalsOnly && <span className="text-[8px] bg-stone-100 text-stone-400 px-1 rounded">VOCALS</span>}
      </p>
    </div>
  </div>
);

export default Search;

import React, { useState } from 'react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music } from 'lucide-react';

type Tab = 'favorites' | 'downloads';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const { favorites, isDownloaded, playTrack, currentTrack, tracks } = useAudio();

  const favoriteTracks = tracks.filter(t => favorites.includes(t.id));
  const downloadedTracks = tracks.filter(t => isDownloaded(t.id));

  const displayTracks = activeTab === 'favorites' ? favoriteTracks : downloadedTracks;

  return (
    <div className="p-6 min-h-full">
      <h1 className="text-2xl font-bold mb-8 text-stone-900 font-serif">Your Library</h1>

      {/* Tabs - Glass Pill */}
      <div className="flex p-1 bg-stone-200/50 rounded-2xl mb-8 relative">
        <button 
          onClick={() => setActiveTab('favorites')}
          className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all ${activeTab === 'favorites' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
        >
          Favorites
        </button>
        <button 
          onClick={() => setActiveTab('downloads')}
          className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all ${activeTab === 'downloads' ? 'bg-white text-stone-800 shadow-sm' : 'text-stone-500 hover:text-stone-700'}`}
        >
          Downloads
        </button>
      </div>

      {/* Content */}
      <div className="space-y-2">
        {displayTracks.length > 0 ? (
          displayTracks.map(track => (
            <LibraryItem key={track.id} track={track} onClick={() => playTrack(track)} isActive={currentTrack?.id === track.id} />
          ))
        ) : (
          <EmptyState type={activeTab} />
        )}
      </div>
    </div>
  );
};

const LibraryItem = ({ track, onClick, isActive }: { track: Track, onClick: () => void, isActive: boolean }) => (
  <div 
    onClick={onClick}
    className={`flex items-center gap-4 p-3 rounded-2xl transition-all cursor-pointer border ${isActive ? 'bg-white border-teal-100 shadow-sm' : 'bg-white/40 border-transparent hover:bg-white/60'}`}
  >
    <div className="w-12 h-12 rounded-xl overflow-hidden bg-stone-100 shadow-sm">
      <img src={track.coverUrl} alt="" className="w-full h-full object-cover" />
    </div>
    <div className="flex-1">
      <h4 className={`text-sm font-bold ${isActive ? 'text-teal-800' : 'text-stone-800'}`}>{track.title}</h4>
      <p className="text-xs text-stone-500">{track.artist}</p>
    </div>
    {isActive && <Music size={18} className="text-teal-600" />}
  </div>
);

const EmptyState = ({ type }: { type: Tab }) => (
  <div className="flex flex-col items-center justify-center py-20 text-stone-400">
    <div className="w-20 h-20 rounded-full bg-white border border-stone-100 flex items-center justify-center mb-6 shadow-sm">
      {type === 'favorites' ? <Heart size={32} className="text-stone-300" /> : <Download size={32} className="text-stone-300" />}
    </div>
    <p className="text-base font-bold text-stone-600">No {type} yet</p>
    <p className="text-sm mt-1">Start listening to add to your library.</p>
  </div>
);

export default Library;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { ShieldCheck, Lock, Mail, AlertCircle, ArrowLeft } from 'lucide-react';

const AdminLogin = () => {
