// "Stored" Publisher Account (Simulating Backend Storage)
const PUBLISHER_ACCOUNT = {
  email: 'admin@arbnoor.com',
  password: 'arbnoor@123',
  role: 'publisher'
};

interface AuthContextType {
  isAdmin: boolean; // Maps to role === 'publisher'
  login: (email: string, pass: string) => boolean;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isAdmin, setIsAdmin] = useState(false);

  // Initialize: Check for persisted session
  useEffect(() => {
    const savedSession = localStorage.getItem('arbnoor_publisher_session');
    if (savedSession === 'active') {
      setIsAdmin(true);
    }
  }, []);

  const login = (email: string, pass: string) => {
    // Strict validation against the "Stored" Publisher Account
    if (email === PUBLISHER_ACCOUNT.email && pass === PUBLISHER_ACCOUNT.password) {
      setIsAdmin(true);
      // Persist session to local storage (simulating a token)
      localStorage.setItem('arbnoor_publisher_session', 'active');
      return true;
    }
    return false;
  };

  const logout = () => {
    setIsAdmin(false);
    localStorage.removeItem('arbnoor_publisher_session');
  };

  return (
    <AuthContext.Provider value={{ isAdmin, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

