}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isAdmin: boolean; // Derived helper for ProtectedRoutes
  login: (email: string, pass: string) => boolean;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // 1. Storage: Simulate a backend database for users
  const [userDatabase, setUserDatabase] = useState<User[]>([]);

  // 2. Session: Current active user
  const [user, setUser] = useState<User | null>(null);

  // 3. Initialization: Create and store the publisher account explicitly
  useEffect(() => {
    // "Create publisher user at app initialization"
    const publisherAccount: User = {
      id: 'pub-alpha-001',
      email: 'admin@arbnoor.com',
      password: 'arbnoor@123',
      role: 'publisher',
      name: 'ArbNoor Publisher'
    };

    // Store in our mock database
    setUserDatabase([publisherAccount]);

    // Check for persisted session
    const savedSessionEmail = localStorage.getItem('arbnoor_publisher_session');
    if (savedSessionEmail && savedSessionEmail === publisherAccount.email) {
      // Re-hydrate user from the "database"
      setUser(publisherAccount);
    }
  }, []);

  const login = (email: string, pass: string) => {
    // 4. Logic: Compare entered credentials with stored account in userDatabase
    const foundUser = userDatabase.find(
      (u) => u.email === email && u.password === pass
    );

    if (foundUser) {
      setUser(foundUser);
      // Persist session
      localStorage.setItem('arbnoor_publisher_session', foundUser.email);
      return true;
    }

    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('arbnoor_publisher_session');
  };

  // Helper for existing components that check boolean status
  const isAdmin = user?.role === 'publisher';

  return (
    <AuthContext.Provider value={{ user, isAdmin, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

