           <button onClick={handleLogout} className="text-xs font-bold text-stone-500 hover:text-red-500 flex items-center gap-1.5 bg-stone-100 hover:bg-red-50 px-3 py-2 rounded-xl transition-colors">
             <LogOut size={14} /> <span className="hidden sm:inline">Logout</span>
           </button>
        </div>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

