                <select value={category} onChange={e => setCategory(e.target.value as Category)} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-sm focus:border-teal-500 focus:ring-2 focus:ring-teal-500/20 outline-none transition-all shadow-sm">
