import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAudio } from '../context/AudioContext';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Plus, Trash2, LogOut, Play, Square, CheckCircle, User as UserIcon } from 'lucide-react';
import { Category, Track } from '../types';

const AdminDashboard = () => {
  const { logout, user } = useAuth();
  const { tracks, addTrack, deleteTrack } = useAudio();
  const navigate = useNavigate();

  // Form State
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [category, setCategory] = useState<Category>(Category.NAAT);
  const [url, setUrl] = useState('');
  const [coverUrl, setCoverUrl] = useState('https://picsum.photos/400/400');
  const [isVocalsVerified, setIsVocalsVerified] = useState(false);
  const [previewAudio, setPreviewAudio] = useState<HTMLAudioElement | null>(null);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);

  const handleLogout = () => {
    if (previewAudio) {
      previewAudio.pause();
    }
    logout();
    navigate('/admin/login');
  };

  const handlePreview = () => {
    if (isPreviewPlaying && previewAudio) {
      previewAudio.pause();
      setIsPreviewPlaying(false);
    } else {
      if (!url) return;
      const audio = new Audio(url);
      audio.onended = () => setIsPreviewPlaying(false);
      audio.play().catch(e => alert("Could not play audio url. Check link."));
      setPreviewAudio(audio);
      setIsPreviewPlaying(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isVocalsVerified) {
      alert("You must verify that the content is Vocals Only.");
      return;
    }

    const newTrack: Track = {
      id: Date.now().toString(),
      title,
      artist,
      category,
      url,
      coverUrl,
      duration: 0, // In a real app, we'd extract metadata
      isVocalsOnly: true
    };

    addTrack(newTrack);
    // Reset form
    setTitle('');
    setArtist('');
    setUrl('');
    setIsVocalsVerified(false);
    alert("Track published successfully!");
  };

  return (
    <div className="min-h-screen text-stone-800">
      {/* Navbar - Glass */}
      <div className="bg-white/80 backdrop-blur-md border-b border-stone-200/50 p-4 flex justify-between items-center sticky top-0 z-20 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-teal-50 rounded-lg flex items-center justify-center border border-teal-100">
             <ShieldCheck size={18} className="text-teal-700" />
          </div>
          <div>
            <h1 className="font-bold text-stone-900 font-serif text-lg leading-tight">Publisher Dashboard</h1>
            <div className="flex items-center gap-1.5 text-[10px] text-teal-600 font-medium bg-teal-50 px-2 py-0.5 rounded-full w-fit">
              <span className="w-1.5 h-1.5 bg-teal-500 rounded-full animate-pulse"></span>
              {user?.role?.toUpperCase()} ACCESS
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:flex items-center gap-2 text-right">
             <div className="text-xs">
               <p className="font-bold text-stone-800">{user?.name}</p>
               <p className="text-stone-400">{user?.email}</p>
             </div>
             <div className="w-8 h-8 bg-stone-100 rounded-full flex items-center justify-center text-stone-400">
               <UserIcon size={16} />
             </div>
           </div>
           <button onClick={handleLogout} className="text-xs font-bold text-stone-500 hover:text-red-500 flex items-center gap-1.5 bg-stone-100 hover:bg-red-50 px-3 py-2 rounded-xl transition-colors">
             <LogOut size={14} /> <span className="hidden sm:inline">Logout</span>
           </button>
        </div>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Upload Form */}
        <div className="lg:col-span-1">
          <div className="bg-white/70 backdrop-blur-xl rounded-[2rem] border border-white/60 p-6 shadow-xl shadow-stone-200/30 sticky top-24">
            <h2 className="text-lg font-bold text-stone-800 mb-6 flex items-center gap-2">
              <span className="w-8 h-8 rounded-full bg-amber-100 text-amber-600 flex items-center justify-center"><Plus size={20} /></span>
              Upload Content
            </h2>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-1.5 ml-1">Title</label>
                <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-sm focus:border-teal-500 focus:ring-2 focus:ring-teal-500/20 outline-none transition-all shadow-sm" placeholder="e.g. Maula Ya Salli" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-1.5 ml-1">Reciter / Artist</label>
                <input required value={artist} onChange={e => setArtist(e.target.value)} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-sm focus:border-teal-500 focus:ring-2 focus:ring-teal-500/20 outline-none transition-all shadow-sm" placeholder="e.g. Junaid Jamshed" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-1.5 ml-1">Category</label>
                <select value={category} onChange={e => setCategory(e.target.value as Category)} className="w-full bg-white border border-stone-200 rounded-xl p-3 text-sm focus:border-teal-500 focus:ring-2 focus:ring-teal-500/20 outline-none transition-all shadow-sm">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-1.5 ml-1">Audio URL</label>
