                  <input type="checkbox" className="hidden" checked={isVocalsVerified} onChange={e => setIsVocalsVerified(e.target.checked)} />
                  <div className="text-xs text-stone-600">
                    <span className="font-bold text-teal-800 block mb-1">Vocals Only Verification</span>
                    I certify that this audio file does NOT contain any musical instruments, beats, or non-compliant background music.
                  </div>
                </label>
              </div>

              <button type="submit" className="w-full bg-stone-900 hover:bg-stone-800 text-white font-bold py-4 rounded-xl transition-all shadow-lg active:scale-95">
                Publish Track
              </button>
            </form>
          </div>
        </div>

        {/* Manage Content List */}
        <div className="lg:col-span-2">
          <div className="bg-white/70 backdrop-blur-xl rounded-[2rem] border border-white/60 overflow-hidden shadow-xl shadow-stone-200/30">
             <div className="p-6 border-b border-stone-200/50 bg-white/40">
                <h2 className="text-lg font-bold text-stone-900">Manage Content</h2>
             </div>
             <div className="divide-y divide-stone-100 max-h-[600px] overflow-y-auto">
                {tracks.map(track => (
                  <div key={track.id} className="p-4 flex items-center gap-4 hover:bg-white/80 transition-colors">
                    <img src={track.coverUrl} className="w-12 h-12 rounded-xl bg-stone-200 object-cover shadow-sm" alt="" />
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <h4 className="text-sm font-bold text-stone-800 truncate">{track.title}</h4>
