import React, { useState } from 'react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music } from 'lucide-react';

type Tab = 'favorites' | 'downloads';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const { favorites, isDownloaded, playTrack, currentTrack, tracks } = useAudio();

  const favoriteTracks = tracks.filter(t => favorites.includes(t.id));
  const downloadedTracks = tracks.filter(t => isDownloaded(t.id));

  const displayTracks = activeTab === 'favorites' ? favoriteTracks : downloadedTracks;

  return (
    <div className="p-6 min-h-full pb-32">
      <h1 className="text-3xl font-bold mb-8 text-stone-800 font-serif">Your Library</h1>

      {/* Tabs - Glass Pill */}
      <div className="flex p-1.5 bg-white/40 backdrop-blur-xl border border-white/50 rounded-full mb-8 relative shadow-inner">
        <button 
          onClick={() => setActiveTab('favorites')}
          className={`flex-1 py-3 text-sm font-bold rounded-full transition-all ${activeTab === 'favorites' ? 'bg-white text-teal-900 shadow-md' : 'text-stone-500 hover:text-stone-700'}`}
        >
          Favorites
        </button>
        <button 
          onClick={() => setActiveTab('downloads')}
          className={`flex-1 py-3 text-sm font-bold rounded-full transition-all ${activeTab === 'downloads' ? 'bg-white text-teal-900 shadow-md' : 'text-stone-500 hover:text-stone-700'}`}
        >
          Downloads
        </button>
      </div>

      {/* Content */}
      <div className="space-y-3">
        {displayTracks.length > 0 ? (
          displayTracks.map(track => (
            <LibraryItem key={track.id} track={track} onClick={() => playTrack(track)} isActive={currentTrack?.id === track.id} />
          ))
        ) : (
          <EmptyState type={activeTab} />
        )}
      </div>
    </div>
  );
};

const LibraryItem = ({ track, onClick, isActive }: { track: Track, onClick: () => void, isActive: boolean }) => (
  <div 
    onClick={onClick}
    className={`flex items-center gap-4 p-3 rounded-3xl transition-all cursor-pointer border ${isActive ? 'bg-white/80 border-teal-100 shadow-md' : 'bg-white/30 border-transparent hover:bg-white/50 hover:border-white/40'}`}
  >
    <div className="w-14 h-14 rounded-2xl overflow-hidden bg-stone-100 shadow-sm border border-white/30">
      <img src={track.coverUrl} alt="" className="w-full h-full object-cover" />
    </div>
    <div className="flex-1 min-w-0">
      <h4 className={`text-sm font-bold truncate ${isActive ? 'text-teal-900' : 'text-stone-800'}`}>{track.title}</h4>
      <p className="text-xs text-stone-500 mt-1">{track.artist}</p>
    </div>
    {isActive && <div className="w-8 h-8 rounded-full bg-teal-50 flex items-center justify-center"><Music size={16} className="text-teal-600" /></div>}
  </div>
);

const EmptyState = ({ type }: { type: Tab }) => (
  <div className="flex flex-col items-center justify-center py-20 text-stone-400">
    <div className="w-24 h-24 rounded-full bg-white/40 border border-white/60 flex items-center justify-center mb-6 shadow-sm backdrop-blur-sm">
      {type === 'favorites' ? <Heart size={36} className="text-stone-300" /> : <Download size={36} className="text-stone-300" />}
    </div>
    <p className="text-lg font-serif font-bold text-stone-600">No {type} yet</p>
    <p className="text-sm mt-2 text-stone-400">Start listening to build your collection.</p>
