);

export default Library;

import React, { useState } from 'react';
import { ChevronDown, Play, Pause, SkipBack, SkipForward, Heart, Moon, Share2, Download, ListMusic, ShieldCheck } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

interface PlayerOverlayProps {
  isOpen: boolean;
  onClose: () => void;
}

const PlayerOverlay: React.FC<PlayerOverlayProps> = ({ isOpen, onClose }) => {
  const { 
    currentTrack, 
    isPlaying, 
    togglePlay, 
    playNext, 
    playPrev, 
    seek, 
    duration, 
    currentTime,
    favorites,
    toggleFavorite,
    sleepTimer,
    setSleepTimer,
    isDownloaded,
    toggleDownload
  } = useAudio();

  const [showSleepOptions, setShowSleepOptions] = useState(false);

  if (!isOpen || !currentTrack) return null;

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
  };

  const isFav = favorites.includes(currentTrack.id);
  const isDown = isDownloaded(currentTrack.id);

  return (
    <div className="fixed inset-0 z-50 flex flex-col transition-all duration-500 ease-out bg-[#F7F5F0]/90 backdrop-blur-[40px]">
      {/* Background Ambience Blob */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[350px] h-[350px] bg-teal-400/10 rounded-full blur-[120px] pointer-events-none"></div>
      <div className="absolute top-0 left-0 w-full h-full bg-noise opacity-[0.03] pointer-events-none"></div>

      {/* Header */}
      <div className="relative flex justify-between items-center p-6 mt-6 z-10">
        <button onClick={onClose} className="p-3 text-stone-600 hover:text-stone-900 transition-colors bg-white/40 backdrop-blur-md rounded-full shadow-sm border border-white/50 active:scale-90">
          <ChevronDown size={24} />
        </button>
        <div className="flex flex-col items-center">
          <span className="text-[10px] uppercase tracking-[0.2em] text-stone-500 font-bold">Now Playing</span>
        </div>
        <button 
          onClick={() => setShowSleepOptions(!showSleepOptions)} 
          className={`p-3 rounded-full transition-colors border border-white/50 shadow-sm ${sleepTimer ? 'text-amber-600 bg-amber-50/80' : 'text-stone-400 hover:text-stone-800 bg-white/40 backdrop-blur-md'}`}
        >
          <Moon size={20} fill={sleepTimer ? "currentColor" : "none"} />
        </button>
      </div>

      {/* Sleep Timer Menu */}
      {showSleepOptions && (
        <div className="absolute top-24 right-6 bg-white/80 backdrop-blur-2xl border border-white/60 rounded-3xl shadow-2xl shadow-stone-300/50 p-2 w-48 z-50 animate-in fade-in zoom-in-95 duration-200">
          <p className="text-xs text-stone-400 px-4 py-3 uppercase font-bold tracking-wider border-b border-stone-100">Sleep Timer</p>
          {[15, 30, 45, 60].map((min) => (
            <button
              key={min}
              onClick={() => {
                setSleepTimer(min);
                setShowSleepOptions(false);
              }}
              className="block w-full text-left px-4 py-3 text-sm text-stone-700 hover:bg-stone-100/50 rounded-2xl font-medium transition-colors"
            >
              {min} Minutes
            </button>
          ))}
          <button
            onClick={() => {
              setSleepTimer(null);
              setShowSleepOptions(false);
            }}
            className="block w-full text-left px-4 py-3 text-sm text-red-500 hover:bg-red-50/50 rounded-2xl font-medium transition-colors"
          >
            Turn Off
          </button>
        </div>
      )}

      {/* Main Content */}
      <div className="relative flex-1 flex flex-col items-center justify-center px-8 z-10">
        {/* Album Art Card */}
        <div className="w-full max-w-xs aspect-square bg-white/40 backdrop-blur-sm rounded-[2.5rem] shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] p-4 mb-10 border border-white/60 relative">
          <div className="w-full h-full rounded-[2rem] overflow-hidden relative shadow-inner">
            <img 
              src={currentTrack.coverUrl} 
              alt={currentTrack.title} 
              className="w-full h-full object-cover"
            />
            {currentTrack.isVocalsOnly && (
               <div className="absolute top-4 right-4">
                 <span className="bg-white/30 backdrop-blur-xl text-white px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5 shadow-lg border border-white/40">
                   <ShieldCheck size={12} />
                   Vocals
                 </span>
               </div>
            )}
          </div>
        </div>

        {/* Track Info */}
        <div className="w-full max-w-sm flex justify-between items-center mb-8 px-2">
          <div className="flex-1 pr-4">
            <h2 className="text-2xl font-bold text-stone-800 mb-1 leading-tight font-serif">{currentTrack.title}</h2>
            <p className="text-teal-700 text-lg font-medium opacity-80">{currentTrack.artist}</p>
          </div>
          <button 
            onClick={() => toggleFavorite(currentTrack.id)}
            className={`p-4 rounded-full transition-all active:scale-90 ${isFav ? 'bg-red-50 text-red-500 shadow-inner' : 'bg-transparent text-stone-300 hover:text-stone-500'}`}
          >
            <Heart size={26} fill={isFav ? "currentColor" : "none"} />
          </button>
        </div>

        {/* Progress Bar */}
        <div className="w-full max-w-sm mb-6 px-2 group">
          <input
            type="range"
            min="0"
            max={duration || 100}
            value={currentTime}
            onChange={(e) => seek(Number(e.target.value))}
            className="w-full h-2 bg-stone-200/60 rounded-full appearance-none cursor-pointer accent-teal-600 hover:accent-teal-500 transition-all"
          />
          <div className="flex justify-between mt-3 text-xs text-stone-400 font-bold font-mono tracking-wide">
            <span>{formatTime(currentTime)}</span>
            <span>{formatTime(duration)}</span>
          </div>
        </div>

        {/* Controls */}
        <div className="w-full max-w-sm flex justify-between items-center mt-2 mb-12 px-2">
          <button onClick={playPrev} className="text-stone-400 hover:text-stone-800 transition-all active:scale-90 p-4 hover:bg-white/40 rounded-full">
            <SkipBack size={30} fill="currentColor" className="opacity-80"/>
          </button>

          <button 
            onClick={togglePlay} 
            className="bg-stone-800 text-[#F7F5F0] rounded-[2.5rem] p-8 hover:bg-stone-900 transition-all active:scale-90 shadow-[0_15px_30px_rgba(28,25,23,0.25)] border-4 border-[#F7F5F0]"
          >
            {isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
          </button>

          <button onClick={playNext} className="text-stone-400 hover:text-stone-800 transition-all active:scale-90 p-4 hover:bg-white/40 rounded-full">
            <SkipForward size={30} fill="currentColor" className="opacity-80" />
          </button>
        </div>

        {/* Action Buttons */}
        <div className="w-full max-w-xs flex justify-between items-center px-6 py-4 bg-white/40 backdrop-blur-xl rounded-full border border-white/50 shadow-sm">
          <button 
            onClick={() => toggleDownload(currentTrack.id)}
            className={`p-2 transition-colors active:scale-95 ${isDown ? 'text-teal-600' : 'text-stone-400 hover:text-stone-600'}`}
          >
            <Download size={22} strokeWidth={isDown ? 2.5 : 2} />
          </button>
          <div className="w-px h-6 bg-stone-200"></div>
          <button className="p-2 text-stone-400 hover:text-stone-600 transition-colors active:scale-95">
            <Share2 size={22} />
          </button>
          <div className="w-px h-6 bg-stone-200"></div>
          <button className="p-2 text-stone-400 hover:text-stone-600 transition-colors active:scale-95">
            <ListMusic size={22} />
          </button>
        </div>
      </div>

      {/* Bottom Spacer for safe area */}
      <div className="h-8"></div>
    </div>
  );
};

export default PlayerOverlay;

