import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAudio } from '../context/AudioContext';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Plus, Trash2, LogOut, Play, Square, CheckCircle, User as UserIcon } from 'lucide-react';
import { Category, Track } from '../types';

const AdminDashboard = () => {
  const { logout, user } = useAuth();
  const { tracks, addTrack, deleteTrack } = useAudio();
  const navigate = useNavigate();

  // Form State
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [category, setCategory] = useState<Category>(Category.NAAT);
  const [url, setUrl] = useState('');
  const [coverUrl, setCoverUrl] = useState('https://picsum.photos/400/400');
  const [isVocalsVerified, setIsVocalsVerified] = useState(false);
  const [previewAudio, setPreviewAudio] = useState<HTMLAudioElement | null>(null);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);

  const handleLogout = () => {
    if (previewAudio) {
      previewAudio.pause();
    }
    logout();
    navigate('/admin/login');
  };

  const handlePreview = () => {
    if (isPreviewPlaying && previewAudio) {
      previewAudio.pause();
      setIsPreviewPlaying(false);
    } else {
      if (!url) return;
      const audio = new Audio(url);
      audio.onended = () => setIsPreviewPlaying(false);
      audio.play().catch(e => alert("Could not play audio url. Check link."));
      setPreviewAudio(audio);
      setIsPreviewPlaying(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isVocalsVerified) {
      alert("You must verify that the content is Vocals Only.");
      return;
    }

    const newTrack: Track = {
      id: Date.now().toString(),
      title,
      artist,
      category,
      url,
      coverUrl,
      duration: 0, // In a real app, we'd extract metadata
      isVocalsOnly: true
    };

    addTrack(newTrack);
    // Reset form
    setTitle('');
    setArtist('');
    setUrl('');
    setIsVocalsVerified(false);
    alert("Track published successfully!");
  };

  return (
    <div className="min-h-screen text-stone-800 font-sans pb-20">
      {/* Navbar - Glass */}
      <div className="bg-white/70 backdrop-blur-xl border-b border-white/50 p-4 flex justify-between items-center sticky top-0 z-20 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-teal-50/80 rounded-xl flex items-center justify-center border border-teal-100/50 shadow-sm">
             <ShieldCheck size={20} className="text-teal-700" />
          </div>
          <div>
            <h1 className="font-bold text-stone-800 font-serif text-xl leading-none">Publisher</h1>
            <div className="flex items-center gap-1.5 text-[9px] tracking-wider text-teal-700 font-bold uppercase mt-1">
              <span className="w-1.5 h-1.5 bg-teal-500 rounded-full animate-pulse"></span>
              Secure Access
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <div className="hidden md:flex items-center gap-3 text-right bg-white/40 px-3 py-1.5 rounded-2xl border border-white/50">
             <div className="text-xs">
               <p className="font-bold text-stone-800">{user?.name}</p>
             </div>
             <div className="w-7 h-7 bg-stone-100 rounded-full flex items-center justify-center text-stone-400">
               <UserIcon size={14} />
             </div>
           </div>
           <button onClick={handleLogout} className="text-xs font-bold text-stone-500 hover:text-red-500 flex items-center gap-2 bg-white/60 hover:bg-red-50 px-4 py-2.5 rounded-xl transition-colors border border-white/60 shadow-sm">
             <LogOut size={14} /> <span className="hidden sm:inline">Logout</span>
           </button>
        </div>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Upload Form */}
        <div className="lg:col-span-1">
          <div className="bg-white/60 backdrop-blur-2xl rounded-[2.5rem] border border-white/60 p-8 shadow-xl shadow-stone-200/20 sticky top-28">
            <h2 className="text-xl font-bold text-stone-800 mb-8 flex items-center gap-3">
              <span className="w-10 h-10 rounded-2xl bg-amber-100/80 text-amber-700 flex items-center justify-center border border-amber-200/50"><Plus size={22} /></span>
              Upload Content
            </h2>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Title</label>
                <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-white/80 border border-stone-100 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium" placeholder="e.g. Maula Ya Salli" />
              </div>

