import React, { createContext, useContext, useEffect, useState } from 'react';
import { ThemeMode } from '../types';

interface ThemeContextType {
  theme: ThemeMode;
  setTheme: (theme: ThemeMode) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error('useTheme must be used within ThemeProvider');
  return context;
};

export const ThemeProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<ThemeMode>(() => {
    return (localStorage.getItem('arbnoor_theme') as ThemeMode) || 'system';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    const systemDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    // Remove previous classes
    root.classList.remove('light', 'dark');

    if (theme === 'system') {
      root.classList.add(systemDark ? 'dark' : 'light');
    } else {
      root.classList.add(theme);
    }

    localStorage.setItem('arbnoor_theme', theme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

import React, { createContext, useContext, useState, useRef, useEffect, useCallback } from 'react';
import { Track, AudioQuality } from '../types';
import { TRACKS as INITIAL_TRACKS } from '../constants';

interface AudioContextType {
  tracks: Track[];
  currentTrack: Track | null;
  isPlaying: boolean;
  progress: number;
  currentTime: number;
  duration: number;
  playTrack: (track: Track) => void;
  togglePlay: () => void;
  playNext: () => void;
  playPrev: () => void;
  seek: (time: number) => void;
  toggleFavorite: (trackId: string) => void;
  favorites: string[];
  history: Track[]; // Listening history
  sleepTimer: number | null;
  setSleepTimer: (minutes: number | null) => void;
  isDownloaded: (trackId: string) => boolean;
  toggleDownload: (trackId: string) => void;
  audioQuality: AudioQuality;
  setAudioQuality: (q: AudioQuality) => void;
  // Admin functions
  addTrack: (track: Track) => void;
  deleteTrack: (trackId: string) => void;
}

const AudioContext = createContext<AudioContextType | undefined>(undefined);

export const useAudio = () => {
  const context = useContext(AudioContext);
  if (!context) {
    throw new Error('useAudio must be used within an AudioProvider');
  }
  return context;
};

export const AudioProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [tracks, setTracks] = useState<Track[]>(INITIAL_TRACKS);
  const [currentTrack, setCurrentTrack] = useState<Track | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  // Persistence
  const [favorites, setFavorites] = useState<string[]>(() => {
    const saved = localStorage.getItem('arbnoor_favorites');
    return saved ? JSON.parse(saved) : [];
  });
  const [downloads, setDownloads] = useState<string[]>(() => {
    const saved = localStorage.getItem('arbnoor_downloads');
    return saved ? JSON.parse(saved) : [];
  });
  const [history, setHistory] = useState<Track[]>(() => {
    // In a real app, store IDs and fetch. Here we just store the list (reset on reload if complex)
    // For simplicity in this demo, we start empty to avoid serialization issues with Blobs
    return []; 
  });

  const [audioQuality, setAudioQuality] = useState<AudioQuality>('high');
  const [sleepTimer, setSleepTimerState] = useState<number | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    audioRef.current = new Audio();
    const audio = audioRef.current;

    const updateTime = () => {
      setCurrentTime(audio.currentTime);
      setDuration(audio.duration || 0);
    };

    const handleEnded = () => {
      playNext();
    };

    audio.addEventListener('timeupdate', updateTime);
    audio.addEventListener('loadedmetadata', updateTime);
    audio.addEventListener('ended', handleEnded);

    return () => {
      audio.removeEventListener('timeupdate', updateTime);
      audio.removeEventListener('loadedmetadata', updateTime);
      audio.removeEventListener('ended', handleEnded);
      audio.pause();
    };
  }, []);

  // Sleep Timer
  useEffect(() => {
    if (sleepTimer !== null) {
      if (sleepTimer <= 0) {
        if (audioRef.current) audioRef.current.pause();
        setIsPlaying(false);
        setSleepTimerState(null);
        return;
      }
      timerRef.current = window.setTimeout(() => {
        setSleepTimerState(prev => (prev ? prev - 1 : null));
      }, 60000);
    }
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [sleepTimer]);

  const addToHistory = (track: Track) => {
    setHistory(prev => {
      const filtered = prev.filter(t => t.id !== track.id);
      return [track, ...filtered].slice(0, 10); // Keep last 10
    });
  };

  const playTrack = (track: Track) => {
    if (audioRef.current) {
      if (currentTrack?.id === track.id) {
        togglePlay();
        return;
      }

      // Simulate Quality Logic (In real app, select different URL)
      console.log(`Playing ${track.title} at ${audioQuality} quality`);

      setCurrentTrack(track);
      addToHistory(track);

      audioRef.current.src = track.url;
      audioRef.current.play().then(() => {
        setIsPlaying(true);
      }).catch(e => console.error("Playback failed", e));
    }
  };

  const togglePlay = () => {
    if (audioRef.current && currentTrack) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play().catch(e => console.error(e));
        setIsPlaying(true);
      }
    }
  };

  const seek = (time: number) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const playNext = useCallback(() => {
    if (!currentTrack) return;
    const currentIndex = tracks.findIndex(t => t.id === currentTrack.id);
    if (currentIndex === -1) return;
    const nextIndex = (currentIndex + 1) % tracks.length;
    playTrack(tracks[nextIndex]);
  }, [currentTrack, tracks]);

  const playPrev = useCallback(() => {
    if (!currentTrack) return;
    const currentIndex = tracks.findIndex(t => t.id === currentTrack.id);
    if (currentIndex === -1) return;
    const prevIndex = (currentIndex - 1 + tracks.length) % tracks.length;
    playTrack(tracks[prevIndex]);
  }, [currentTrack, tracks]);

  const toggleFavorite = (trackId: string) => {
    setFavorites(prev => {
      const newFavs = prev.includes(trackId) 
        ? prev.filter(id => id !== trackId)
        : [...prev, trackId];
      localStorage.setItem('arbnoor_favorites', JSON.stringify(newFavs));
      return newFavs;
    });
  };

  const toggleDownload = (trackId: string) => {
    setDownloads(prev => {
      const newDownloads = prev.includes(trackId)
        ? prev.filter(id => id !== trackId)
        : [...prev, trackId];
      localStorage.setItem('arbnoor_downloads', JSON.stringify(newDownloads));
      return newDownloads;
    });
  };

  const isDownloaded = (trackId: string) => downloads.includes(trackId);

  const addTrack = (track: Track) => {
    setTracks(prev => [track, ...prev]);
  };

  const deleteTrack = (trackId: string) => {
    setTracks(prev => prev.filter(t => t.id !== trackId));
    if (currentTrack?.id === trackId) {
      if (audioRef.current) audioRef.current.pause();
      setIsPlaying(false);
      setCurrentTrack(null);
    }
  };

  const progress = duration ? (currentTime / duration) * 100 : 0;

  return (
    <AudioContext.Provider value={{
      tracks,
      currentTrack,
      isPlaying,
      progress,
      currentTime,
      duration,
      playTrack,
      togglePlay,
      playNext,
      playPrev,
      seek,
      toggleFavorite,
      favorites,
      history,
      sleepTimer,
      setSleepTimer,
      isDownloaded,
      toggleDownload,
      audioQuality,
      setAudioQuality,
      addTrack,
      deleteTrack
    }}>
      {children}
    </AudioContext.Provider>
  );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User } from '../types';

interface AuthContextType {
  user: User | null;
  isAdmin: boolean; 
  login: (email: string, pass: string) => boolean;
  logout: () => void;
  switchRole: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);

  // Default Publisher Account
  const publisherAccount: User = {
    id: 'pub-alpha-001',
    email: 'admin@arbnoor.com',
    password: 'arbnoor@123',
    role: 'publisher', // Default role
    name: 'ArbNoor Publisher'
  };

  useEffect(() => {
    const savedSessionEmail = localStorage.getItem('arbnoor_publisher_session');
    if (savedSessionEmail && savedSessionEmail === publisherAccount.email) {
      setUser(publisherAccount);
    } else {
      // Default to a Guest Listener if not logged in as admin
      setUser({
        id: 'guest-01',
        email: 'guest@arbnoor.com',
        role: 'user',
        name: 'Listener'
      });
    }
  }, []);

  const login = (email: string, pass: string) => {
    if (email === publisherAccount.email && pass === publisherAccount.password) {
      setUser(publisherAccount);
      localStorage.setItem('arbnoor_publisher_session', publisherAccount.email);
      return true;
    }
    return false;
  };

  const logout = () => {
    // Revert to guest listener
    setUser({
        id: 'guest-01',
        email: 'guest@arbnoor.com',
        role: 'user',
        name: 'Listener'
      });
    localStorage.removeItem('arbnoor_publisher_session');
  };

  const switchRole = () => {
    if (user) {
        setUser({
            ...user,
            role: user.role === 'publisher' ? 'user' : 'publisher'
        });
    }
  };

  const isAdmin = user?.role === 'publisher';

  return (
    <AuthContext.Provider value={{ user, isAdmin, login, logout, switchRole }}>
      {children}
    </AuthContext.Provider>
  );
};

