import React, { useState, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAudio } from '../context/AudioContext';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Plus, Trash2, LogOut, Play, Square, CheckCircle, User as UserIcon, Upload, Image as ImageIcon, Music } from 'lucide-react';
import { Category, Track } from '../types';

const AdminDashboard = () => {
  const { logout, user } = useAuth();
  const { tracks, addTrack, deleteTrack } = useAudio();
  const navigate = useNavigate();

  // Form State
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [category, setCategory] = useState<Category>(Category.NAAT);

  // File State
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);

  // Previews
  const [audioPreviewUrl, setAudioPreviewUrl] = useState<string>('');
  const [imagePreviewUrl, setImagePreviewUrl] = useState<string>('');

  const [isVocalsVerified, setIsVocalsVerified] = useState(false);
  const [previewAudio, setPreviewAudio] = useState<HTMLAudioElement | null>(null);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);

  // File Refs
  const audioInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  const handleLogout = () => {
    if (previewAudio) {
      previewAudio.pause();
    }
    logout();
    navigate('/account');
  };

  const handleAudioFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type !== 'audio/mpeg' && file.type !== 'audio/mp3') {
        alert("Please upload a valid MP3 file.");
        return;
      }
      setAudioFile(file);
      // Create object URL for preview
      const url = URL.createObjectURL(file);
      setAudioPreviewUrl(url);
    }
  };

  const handleImageFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      const url = URL.createObjectURL(file);
      setImagePreviewUrl(url);
    }
  };

  const handlePreview = () => {
    if (isPreviewPlaying && previewAudio) {
      previewAudio.pause();
      setIsPreviewPlaying(false);
    } else {
      if (!audioPreviewUrl) return;
      const audio = new Audio(audioPreviewUrl);
      audio.onended = () => setIsPreviewPlaying(false);
      audio.play().catch(e => alert("Could not play audio."));
      setPreviewAudio(audio);
      setIsPreviewPlaying(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isVocalsVerified) {
      alert("You must verify that the content is Vocals Only.");
      return;
    }
    if (!audioFile || !imageFile) {
        alert("Both audio and thumbnail files are mandatory.");
        return;
    }

    const newTrack: Track = {
      id: Date.now().toString(),
      title,
      artist,
      category,
      url: audioPreviewUrl, // In real app, this is the S3 URL
      coverUrl: imagePreviewUrl, // In real app, S3 URL
      duration: 0, // Would extract metadata
      isVocalsOnly: true,
      localAudioFile: audioFile,
      localImageFile: imageFile
    };

    addTrack(newTrack);

    // Reset form
    setTitle('');
    setArtist('');
    setAudioFile(null);
    setImageFile(null);
    setAudioPreviewUrl('');
    setImagePreviewUrl('');
    setIsVocalsVerified(false);
    if(audioInputRef.current) audioInputRef.current.value = '';
    if(imageInputRef.current) imageInputRef.current.value = '';

    alert("Track published successfully!");
  };

  return (
    <div className="min-h-screen text-stone-800 dark:text-stone-200 font-sans pb-20 transition-colors duration-300">
      {/* Navbar - Glass */}
      <div className="bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border-b border-white/50 dark:border-slate-700 p-4 flex justify-between items-center sticky top-0 z-20 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-teal-50/80 dark:bg-teal-900/50 rounded-xl flex items-center justify-center border border-teal-100/50 dark:border-teal-800 shadow-sm">
             <ShieldCheck size={20} className="text-teal-700 dark:text-teal-400" />
          </div>
          <div>
            <h1 className="font-bold text-stone-800 dark:text-white font-serif text-xl leading-none">Publisher</h1>
            <div className="flex items-center gap-1.5 text-[9px] tracking-wider text-teal-700 dark:text-teal-400 font-bold uppercase mt-1">
              <span className="w-1.5 h-1.5 bg-teal-500 rounded-full animate-pulse"></span>
              Secure Access
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={handleLogout} className="text-xs font-bold text-stone-500 dark:text-stone-400 hover:text-red-500 flex items-center gap-2 bg-white/60 dark:bg-slate-800/60 hover:bg-red-50 px-4 py-2.5 rounded-xl transition-colors border border-white/60 dark:border-slate-700 shadow-sm">
             <LogOut size={14} /> <span className="hidden sm:inline">Exit</span>
           </button>
        </div>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Upload Form */}
        <div className="lg:col-span-1">
          <div className="bg-white/60 dark:bg-slate-800/60 backdrop-blur-2xl rounded-[2.5rem] border border-white/60 dark:border-slate-700 p-8 shadow-xl shadow-stone-200/20 dark:shadow-none sticky top-28">
            <h2 className="text-xl font-bold text-stone-800 dark:text-white mb-8 flex items-center gap-3">
              <span className="w-10 h-10 rounded-2xl bg-amber-100/80 dark:bg-amber-900/50 text-amber-700 dark:text-amber-400 flex items-center justify-center border border-amber-200/50 dark:border-amber-800"><Plus size={22} /></span>
              Upload Content
            </h2>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Metadata */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Title</label>
                <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium dark:text-white" placeholder="e.g. Maula Ya Salli" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Reciter / Artist</label>
                <input required value={artist} onChange={e => setArtist(e.target.value)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium dark:text-white" placeholder="e.g. Junaid Jamshed" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Category</label>
                <div className="relative">
                    <select value={category} onChange={e => setCategory(e.target.value as Category)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium appearance-none dark:text-white">
                    {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>
              </div>

              {/* Audio Upload */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Audio File (MP3)</label>
                <div className={`border-2 border-dashed rounded-2xl p-4 flex flex-col items-center justify-center text-center transition-colors ${audioFile ? 'border-teal-400 bg-teal-50/50 dark:bg-teal-900/20' : 'border-stone-200 dark:border-slate-600 hover:border-teal-300'}`}>
                    <input 
                        type="file" 
                        accept="audio/mp3,audio/mpeg" 
                        ref={audioInputRef}
                        onChange={handleAudioFileChange}
                        className="hidden" 
                        id="audio-upload"
                    />
                    <label htmlFor="audio-upload" className="cursor-pointer w-full flex flex-col items-center">
                        {audioFile ? (
                            <>
                                <Music size={24} className="text-teal-600 mb-2" />
                                <span className="text-xs font-bold text-teal-800 dark:text-teal-300 truncate w-full">{audioFile.name}</span>
                                <button type="button" onClick={handlePreview} className="mt-2 text-[10px] bg-white dark:bg-slate-700 border border-stone-200 dark:border-slate-600 px-3 py-1 rounded-full font-bold flex items-center gap-1 shadow-sm">
                                    {isPreviewPlaying ? <Square size={10} className="text-red-500" fill="currentColor"/> : <Play size={10} className="text-teal-600" fill="currentColor"/>}
                                    Preview
                                </button>
                            </>
                        ) : (
                            <>
                                <Upload size={24} className="text-stone-300 mb-2" />
                                <span className="text-xs font-bold text-stone-500">Click to upload MP3</span>
                            </>
                        )}
                    </label>
                </div>
              </div>

              {/* Thumbnail Upload */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Thumbnail Image</label>
                <div className={`border-2 border-dashed rounded-2xl p-4 flex flex-col items-center justify-center text-center transition-colors relative overflow-hidden ${imageFile ? 'border-teal-400' : 'border-stone-200 dark:border-slate-600 hover:border-teal-300'}`}>
                    <input 
                        type="file" 
                        accept="image/*" 
                        ref={imageInputRef}
                        onChange={handleImageFileChange}
                        className="hidden" 
                        id="image-upload"
                    />
                    <label htmlFor="image-upload" className="cursor-pointer w-full flex flex-col items-center relative z-10">
                         {imageFile ? (
                             <>
                                <span className="text-xs font-bold text-teal-800 dark:text-teal-300 truncate w-full bg-white/80 dark:bg-black/50 px-2 py-1 rounded mb-2">{imageFile.name}</span>
                                <p className="text-[10px] text-stone-500">Click to change</p>
                             </>
                         ) : (
                            <>
                                <ImageIcon size={24} className="text-stone-300 mb-2" />
                                <span className="text-xs font-bold text-stone-500">No faces • Islamic Patterns</span>
                            </>
                         )}
                    </label>
                    {imagePreviewUrl && (
                        <div className="absolute inset-0 z-0 opacity-30">
                            <img src={imagePreviewUrl} alt="Preview" className="w-full h-full object-cover" />
                        </div>
                    )}
                </div>
              </div>


              <div className="bg-teal-50/50 dark:bg-teal-900/20 border border-teal-100/50 dark:border-teal-800/50 rounded-3xl p-5">
                <label className="flex items-start gap-3 cursor-pointer">
                  <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center flex-shrink-0 transition-all ${isVocalsVerified ? 'bg-teal-600 border-teal-600' : 'border-stone-300 dark:border-slate-600 bg-white dark:bg-slate-700'}`}>
                    {isVocalsVerified && <CheckCircle size={14} className="text-white" />}
                  </div>
                  <input type="checkbox" className="hidden" checked={isVocalsVerified} onChange={e => setIsVocalsVerified(e.target.checked)} />
                  <div className="text-xs text-stone-600 dark:text-stone-400">
                    <span className="font-bold text-teal-800 dark:text-teal-400 block mb-1">Vocals Only Verification</span>
                    I certify that this audio file does NOT contain any musical instruments, beats, or non-compliant background music.
                  </div>
                </label>
              </div>

              <button type="submit" className="w-full bg-stone-800 hover:bg-stone-900 dark:bg-teal-600 dark:hover:bg-teal-700 text-white font-bold py-5 rounded-2xl transition-all shadow-xl shadow-stone-800/20 active:scale-95">
                Publish Track
              </button>
            </form>
          </div>
        </div>

        {/* Manage Content List */}
        <div className="lg:col-span-2">
          <div className="bg-white/60 dark:bg-slate-800/60 backdrop-blur-2xl rounded-[2.5rem] border border-white/60 dark:border-slate-700 overflow-hidden shadow-xl shadow-stone-200/20 dark:shadow-none">
             <div className="p-8 border-b border-stone-100/50 dark:border-slate-700 bg-white/40 dark:bg-slate-900/40 backdrop-blur-sm">
                <h2 className="text-xl font-bold text-stone-800 dark:text-white">Manage Content</h2>
                <p className="text-xs text-stone-500 dark:text-stone-400 mt-1">Review and manage your published library</p>
             </div>
             <div className="divide-y divide-stone-100/60 dark:divide-slate-700 max-h-[650px] overflow-y-auto p-2">
                {tracks.map(track => (
                  <div key={track.id} className="p-4 flex items-center gap-5 hover:bg-white/50 dark:hover:bg-slate-700/50 transition-colors rounded-2xl m-2">
                    <div className="w-16 h-16 rounded-2xl bg-stone-100 dark:bg-slate-700 overflow-hidden border border-white/50 dark:border-slate-600 shadow-sm flex-shrink-0">
                        <img src={track.coverUrl} className="w-full h-full object-cover" alt="" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h4 className="text-sm font-bold text-stone-800 dark:text-stone-200 truncate">{track.title}</h4>
                        <span className="text-[10px] bg-white dark:bg-slate-700 border border-stone-100 dark:border-slate-600 px-2 py-0.5 rounded-full text-stone-500 dark:text-stone-400 font-bold uppercase tracking-wide shadow-sm">{track.category}</span>
                      </div>
                      <p className="text-xs text-stone-500 dark:text-stone-400 font-medium">{track.artist}</p>
                    </div>
                    <button 
                      onClick={() => deleteTrack(track.id)}
                      className="p-3 text-stone-400 hover:text-red-600 hover:bg-red-50/50 dark:hover:bg-red-900/30 rounded-xl transition-all"
                      title="Delete Content"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                ))}
             </div>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;

