            <div className="relative w-12 h-12 rounded-full overflow-hidden flex-shrink-0 border border-white/50 dark:border-slate-600 shadow-sm animate-[spin_10s_linear_infinite]" style={{ animationPlayState: isPlaying ? 'running' : 'paused' }}>
                <img 
