      <div className="space-y-3">
        {query.length > 0 ? (
          filteredTracks.length > 0 ? (
            filteredTracks.map(track => (
              <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
            ))
          ) : (
            <div className="text-center py-10 text-stone-400">
              <p>No results found for "{query}"</p>
            </div>
          )
        ) : (
          <div>
            <h3 className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-4 px-2">Browse All Content</h3>
            <div className="bg-white/30 backdrop-blur-md rounded-[2rem] p-3 border border-white/50 shadow-sm">
              {tracks.map(track => (
                <SearchItem key={track.id} track={track} onClick={() => playTrack(track)} active={currentTrack?.id === track.id} />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const SearchItem: React.FC<{ track: Track, onClick: () => void, active: boolean }> = ({ track, onClick, active }) => (
  <div onClick={onClick} className={`flex items-center gap-4 p-3 rounded-2xl cursor-pointer transition-all ${active ? 'bg-white/80 shadow-md ring-1 ring-teal-100' : 'hover:bg-white/40'}`}>
