);

export default Search;

import React, { useState } from 'react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music, ListMusic, Plus, ChevronLeft, Trash2 } from 'lucide-react';

type Tab = 'favorites' | 'downloads' | 'playlists';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const [viewingPlaylistId, setViewingPlaylistId] = useState<string | null>(null);

  const { 
    favorites, 
    isDownloaded, 
    playlists, 
    createPlaylist, 
    deletePlaylist, 
    removeTrackFromPlaylist, 
    playTrack, 
    currentTrack, 
    tracks 
  } = useAudio();

  // Helper to get tracks
  const getTracksByIds = (ids: string[]) => tracks.filter(t => ids.includes(t.id));

  const favoriteTracks = getTracksByIds(favorites);
  const downloadedTracks = tracks.filter(t => isDownloaded(t.id));

  const viewingPlaylist = viewingPlaylistId ? playlists.find(p => p.id === viewingPlaylistId) : null;
  const playlistTracks = viewingPlaylist ? getTracksByIds(viewingPlaylist.trackIds) : [];

  const handleCreatePlaylist = () => {
    const name = prompt("Enter playlist name:");
    if (name && name.trim()) {
      createPlaylist(name.trim());
    }
  };

  const handleDeletePlaylist = () => {
    if (viewingPlaylist && confirm(`Are you sure you want to delete "${viewingPlaylist.name}"?`)) {
      deletePlaylist(viewingPlaylist.id);
      setViewingPlaylistId(null);
    }
  };

  // If viewing a specific playlist, show detail view
  if (viewingPlaylistId && viewingPlaylist) {
    return (
      <div className="p-6 min-h-full pb-32">
        <button 
          onClick={() => setViewingPlaylistId(null)} 
          className="flex items-center gap-2 text-stone-500 hover:text-stone-800 mb-6 transition-colors"
        >
          <ChevronLeft size={20} /> Back
        </button>

        <div className="flex justify-between items-start mb-6">
           <div>
             <h1 className="text-3xl font-bold text-stone-800 dark:text-white font-serif">{viewingPlaylist.name}</h1>
             <p className="text-sm text-stone-500 dark:text-stone-400 mt-1">{playlistTracks.length} Tracks</p>
           </div>
           <button 
             onClick={handleDeletePlaylist}
             className="p-3 bg-red-50 dark:bg-red-900/20 text-red-500 rounded-full hover:bg-red-100 dark:hover:bg-red-900/40 transition-colors"
           >
             <Trash2 size={20} />
           </button>
        </div>

        <div className="space-y-3">
          {playlistTracks.length > 0 ? (
            playlistTracks.map(track => (
              <LibraryItem 
                key={track.id} 
                track={track} 
                onClick={() => playTrack(track)} 
                isActive={currentTrack?.id === track.id}
                onRemove={(e) => {
                  e.stopPropagation();
                  removeTrackFromPlaylist(viewingPlaylist.id, track.id);
                }}
              />
            ))
          ) : (
            <div className="text-center py-20 text-stone-400">
              <Music size={48} className="mx-auto mb-4 opacity-50" />
              <p>This playlist is empty.</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // Default Library View
  return (
    <div className="p-6 min-h-full pb-32">
      <h1 className="text-3xl font-bold mb-8 text-stone-800 dark:text-white font-serif">Your Library</h1>

      {/* Tabs */}
      <div className="flex p-1 bg-white/40 dark:bg-slate-800/40 backdrop-blur-xl border border-white/50 dark:border-slate-700 rounded-full mb-8 relative shadow-inner">
        {(['favorites', 'downloads', 'playlists'] as Tab[]).map((tab) => (
           <button 
           key={tab}
           onClick={() => setActiveTab(tab)}
           className={`flex-1 py-3 text-xs sm:text-sm font-bold rounded-full transition-all capitalize ${activeTab === tab ? 'bg-white dark:bg-slate-700 text-teal-900 dark:text-white shadow-md' : 'text-stone-500 dark:text-stone-400 hover:text-stone-700 dark:hover:text-stone-200'}`}
         >
           {tab}
         </button>
        ))}
      </div>

      {/* Content */}
      <div className="space-y-3">
        {activeTab === 'playlists' ? (
          <>
            <button 
              onClick={handleCreatePlaylist}
              className="w-full py-4 border-2 border-dashed border-stone-300 dark:border-slate-600 rounded-3xl text-stone-500 dark:text-stone-400 font-bold flex items-center justify-center gap-2 hover:bg-white/40 dark:hover:bg-slate-800/40 transition-colors mb-4"
            >
              <Plus size={20} /> Create New Playlist
            </button>

            {playlists.length > 0 ? (
              playlists.map(playlist => (
                <div 
                  key={playlist.id}
                  onClick={() => setViewingPlaylistId(playlist.id)}
                  className="flex items-center gap-4 p-4 rounded-3xl bg-white/40 dark:bg-slate-800/40 border border-white/50 dark:border-slate-700 cursor-pointer hover:bg-white/60 dark:hover:bg-slate-800/60 transition-colors"
                >
                  <div className="w-16 h-16 rounded-2xl bg-teal-50 dark:bg-teal-900/30 flex items-center justify-center text-teal-600 dark:text-teal-400 border border-teal-100 dark:border-teal-800">
                    <ListMusic size={24} />
                  </div>
                  <div className="flex-1">
                    <h4 className="font-bold text-stone-800 dark:text-white">{playlist.name}</h4>
                    <p className="text-xs text-stone-500 dark:text-stone-400 mt-1">{playlist.trackIds.length} Tracks</p>
                  </div>
                  <ChevronLeft size={20} className="rotate-180 text-stone-400" />
                </div>
              ))
            ) : null}
          </>
        ) : (
          (activeTab === 'favorites' ? favoriteTracks : downloadedTracks).length > 0 ? (
            (activeTab === 'favorites' ? favoriteTracks : downloadedTracks).map(track => (
              <LibraryItem key={track.id} track={track} onClick={() => playTrack(track)} isActive={currentTrack?.id === track.id} />
            ))
          ) : (
            <EmptyState type={activeTab} />
          )
        )}
      </div>
    </div>
  );
};

const LibraryItem: React.FC<{ 
  track: Track, 
  onClick: () => void, 
  isActive: boolean, 
  onRemove?: (e: React.MouseEvent) => void 
}> = ({ 
  track, 
  onClick, 
  isActive, 
  onRemove 
}) => (
  <div 
    onClick={onClick}
    className={`flex items-center gap-4 p-3 rounded-3xl transition-all cursor-pointer border ${isActive ? 'bg-white/80 dark:bg-slate-700 border-teal-100 dark:border-teal-900 shadow-md' : 'bg-white/30 dark:bg-slate-800/30 border-transparent hover:bg-white/50 dark:hover:bg-slate-800/50 hover:border-white/40'}`}
  >
    <div className="w-14 h-14 rounded-2xl overflow-hidden bg-stone-100 dark:bg-slate-900 shadow-sm border border-white/30 dark:border-slate-700">
      <img src={track.coverUrl} alt="" className="w-full h-full object-cover" />
    </div>
    <div className="flex-1 min-w-0">
      <h4 className={`text-sm font-bold truncate ${isActive ? 'text-teal-900 dark:text-teal-400' : 'text-stone-800 dark:text-white'}`}>{track.title}</h4>
      <p className="text-xs text-stone-500 dark:text-stone-400 mt-1">{track.artist}</p>
    </div>

    {isActive ? (
      <div className="w-8 h-8 rounded-full bg-teal-50 dark:bg-teal-900/50 flex items-center justify-center">
        <Music size={16} className="text-teal-600 dark:text-teal-400" />
      </div>
    ) : onRemove ? (
      <button 
        onClick={onRemove} 
        className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-red-50 dark:hover:bg-red-900/30 text-stone-400 hover:text-red-500 transition-colors"
      >
        <Trash2 size={18} />
      </button>
    ) : null}
  </div>
);

const EmptyState = ({ type }: { type: Tab }) => (
  <div className="flex flex-col items-center justify-center py-20 text-stone-400">
    <div className="w-24 h-24 rounded-full bg-white/40 dark:bg-slate-800/40 border border-white/60 dark:border-slate-700 flex items-center justify-center mb-6 shadow-sm backdrop-blur-sm">
      {type === 'favorites' ? <Heart size={36} className="text-stone-300 dark:text-stone-500" /> : <Download size={36} className="text-stone-300 dark:text-stone-500" />}
    </div>
    <p className="text-lg font-serif font-bold text-stone-600 dark:text-stone-300 capitalize">No {type} yet</p>
    <p className="text-sm mt-2 text-stone-400">Start listening to build your collection.</p>
  </div>
);

export default Library;

