import React, { useState } from 'react';
import { ChevronDown, Play, Pause, SkipBack, SkipForward, Heart, Moon, Share2, Download, ListMusic, ShieldCheck, Plus, X, MoreHorizontal } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

interface PlayerOverlayProps {
  isOpen: boolean;
  onClose: () => void;
}

const PlayerOverlay: React.FC<PlayerOverlayProps> = ({ isOpen, onClose }) => {
  const { 
    currentTrack, 
    isPlaying, 
    togglePlay, 
    playNext, 
    playPrev, 
    seek, 
    duration, 
    currentTime,
    favorites,
    toggleFavorite,
    sleepTimer,
    setSleepTimer,
    isDownloaded,
    toggleDownload,
    playlists,
    createPlaylist,
    addTrackToPlaylist
  } = useAudio();

  const [showSleepOptions, setShowSleepOptions] = useState(false);
  const [showPlaylistSelector, setShowPlaylistSelector] = useState(false);

  if (!isOpen || !currentTrack) return null;

  const formatTime = (time: number) => {
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
  };

  const isFav = favorites.includes(currentTrack.id);
  const isDown = isDownloaded(currentTrack.id);

  const handleCreateAndAdd = () => {
    const name = prompt("Enter new playlist name:");
    if (name && name.trim()) {
      createPlaylist(name.trim());
    }
  };

  const handleAddToPlaylist = (playlistId: string) => {
    if (currentTrack) {
        addTrackToPlaylist(playlistId, currentTrack.id);
        setShowPlaylistSelector(false);
        alert("Added to playlist!");
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-[#EBEAE6] dark:bg-[#1A1A1A] text-stone-800 dark:text-stone-200">
