        {/* Album Art Container - Floating Glass */}
        <div className="w-full max-w-xs aspect-square glass-panel rounded-[2.5rem] p-3 mb-12 relative shadow-2xl shadow-stone-300/20 dark:shadow-black/40">
           {/* Inner glass layer */}
          <div className="w-full h-full rounded-[2rem] overflow-hidden relative bg-stone-100 dark:bg-stone-800">
            <img 
              src={currentTrack.coverUrl} 
              alt={currentTrack.title} 
              className="w-full h-full object-cover opacity-90"
            />
            {currentTrack.isVocalsOnly && (
               <div className="absolute top-3 right-3 glass-panel px-3 py-1 rounded-full flex items-center gap-1.5">
                 <ShieldCheck size={10} className="text-white" />
                 <span className="text-[8px] font-bold uppercase tracking-widest text-white">Vocals</span>
               </div>
            )}
          </div>
        </div>

        {/* Track Details */}
        <div className="w-full max-w-xs mb-10 text-center">
            <h2 className="text-3xl font-serif text-stone-800 dark:text-white mb-2 leading-tight tracking-wide">{currentTrack.title}</h2>
            <p className="text-sm text-stone-500 dark:text-stone-400 uppercase tracking-[0.2em] font-light">{currentTrack.artist}</p>
        </div>

        {/* Playback Controls */}
        <div className="w-full max-w-xs mb-8">
            {/* Scrubber */}
            <div className="group relative w-full h-8 flex items-center cursor-pointer mb-6" onClick={(e) => {
                 const rect = e.currentTarget.getBoundingClientRect();
                 const x = e.clientX - rect.left;
                 const pct = x / rect.width;
                 seek(pct * duration);
            }}>
                <div className="absolute w-full h-[2px] bg-stone-300 dark:bg-stone-700 rounded-full overflow-hidden">
                     <div className="h-full bg-stone-800 dark:bg-white" style={{ width: `${(currentTime / duration) * 100}%` }}></div>
                </div>
                {/* Thumb */}
                <div 
                    className="absolute w-3 h-3 bg-stone-800 dark:bg-white rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                    style={{ left: `${(currentTime / duration) * 100}%`, transform: 'translateX(-50%)' }}
                ></div>
            </div>

            {/* Time Labels */}
            <div className="flex justify-between text-[10px] text-stone-400 font-medium tracking-widest -mt-4 mb-8">
                <span>{formatTime(currentTime)}</span>
                <span>{formatTime(duration)}</span>
            </div>

            {/* Buttons */}
            <div className="flex justify-between items-center px-2">
                <button onClick={playPrev} className="text-stone-400 dark:text-stone-500 hover:text-stone-800 dark:hover:text-white transition-colors">
                    <SkipBack size={28} strokeWidth={1} />
                </button>

                <button 
                    onClick={togglePlay} 
                    className="w-20 h-20 rounded-full glass-panel flex items-center justify-center hover:bg-white/40 dark:hover:bg-white/10 transition-all active:scale-95 shadow-lg"
                >
                    {isPlaying ? 
                        <Pause size={28} fill="currentColor" strokeWidth={0} className="text-stone-800 dark:text-white" /> : 
                        <Play size={28} fill="currentColor" strokeWidth={0} className="ml-1 text-stone-800 dark:text-white" />
                    }
                </button>

                <button onClick={playNext} className="text-stone-400 dark:text-stone-500 hover:text-stone-800 dark:hover:text-white transition-colors">
                    <SkipForward size={28} strokeWidth={1} />
                </button>
            </div>
        </div>

        {/* Footer Actions */}
        <div className="w-full max-w-xs flex justify-between items-center px-4 mt-auto mb-safe">
          <button 
            onClick={() => toggleFavorite(currentTrack.id)}
            className={`p-3 rounded-full transition-colors ${isFav ? 'text-red-500' : 'text-stone-400 dark:text-stone-600 hover:text-stone-600 dark:hover:text-stone-400'}`}
          >
            <Heart size={20} strokeWidth={1.5} fill={isFav ? "currentColor" : "none"} />
          </button>

          <button 
             onClick={() => setShowPlaylistSelector(true)}
             className="p-3 text-stone-400 dark:text-stone-600 hover:text-stone-600 dark:hover:text-stone-400 transition-colors"
          >
            <Plus size={20} strokeWidth={1.5} />
          </button>

          <button 
             onClick={() => toggleDownload(currentTrack.id)}
             className={`p-3 transition-colors ${isDown ? 'text-stone-800 dark:text-stone-200' : 'text-stone-400 dark:text-stone-600 hover:text-stone-600 dark:hover:text-stone-400'}`}
          >
            <Download size={20} strokeWidth={1.5} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default PlayerOverlay;

