    >
      <div className="relative w-14 h-14 rounded-2xl overflow-hidden flex-shrink-0 shadow-sm">
        <img src={track.coverUrl} alt={track.title} className="w-full h-full object-cover opacity-95 group-hover:opacity-100 transition-opacity" />
