      </div>
      <div className="flex-1 min-w-0 flex flex-col justify-center">
        <h4 className={`text-sm font-bold truncate tracking-wide ${isActive ? 'text-teal-900 dark:text-white' : 'text-stone-700 dark:text-stone-200'}`}>
          {track.title}
        </h4>
        <p className="text-[10px] text-stone-500 dark:text-stone-400 truncate tracking-widest uppercase mt-1 opacity-80 font-medium">{track.artist}</p>
      </div>

      {track.isVocalsOnly && !isActive && (
         <ShieldCheck size={14} className="text-stone-300 dark:text-stone-600" />
