            {/* Scrubber */}
            <div className="group relative w-full h-6 flex items-center cursor-pointer mb-4" onClick={(e) => {
                 const rect = e.currentTarget.getBoundingClientRect();
                 const x = e.clientX - rect.left;
                 const pct = x / rect.width;
                 seek(pct * duration);
            }}>
                <div className="absolute w-full h-[3px] bg-stone-200 dark:bg-slate-700 rounded-full overflow-hidden">
                     <div className="h-full bg-teal-600 dark:bg-teal-400 shadow-[0_0_10px_rgba(20,184,166,0.5)]" style={{ width: `${(currentTime / duration) * 100}%` }}></div>
