                <span>{formatTime(duration)}</span>
            </div>

            {/* Buttons */}
            <div className="flex justify-between items-center px-4">
                <button onClick={playPrev} className="text-stone-400 dark:text-stone-500 hover:text-stone-800 dark:hover:text-white transition-colors p-2 active:scale-90">
                    <SkipBack size={26} strokeWidth={1.5} />
                </button>

                <button 
                    onClick={togglePlay} 
                    className="w-20 h-20 rounded-[2rem] bg-stone-800 dark:bg-white text-[#F2F0E9] dark:text-stone-900 flex items-center justify-center hover:scale-105 transition-transform active:scale-95 shadow-xl shadow-stone-400/30 dark:shadow-none border-4 border-[#F2F0E9] dark:border-slate-800"
                >
                    {isPlaying ? 
                        <Pause size={28} fill="currentColor" strokeWidth={0} /> : 
                        <Play size={28} fill="currentColor" strokeWidth={0} className="ml-1" />
                    }
                </button>

                <button onClick={playNext} className="text-stone-400 dark:text-stone-500 hover:text-stone-800 dark:hover:text-white transition-colors p-2 active:scale-90">
                    <SkipForward size={26} strokeWidth={1.5} />
                </button>
            </div>
        </div>

        {/* Footer Actions - Glass Pill */}
        <div className="w-full max-w-[280px] flex justify-between items-center px-6 py-4 glass-panel rounded-full bg-white/40 dark:bg-white/5 border border-white/50 dark:border-white/10 shadow-sm mt-auto mb-safe">
          <button 
             onClick={() => toggleDownload(currentTrack.id)}
             className={`p-2 transition-colors active:scale-95 ${isDown ? 'text-teal-600 dark:text-teal-400' : 'text-stone-400 dark:text-stone-500 hover:text-stone-600'}`}
          >
            <Download size={20} strokeWidth={isDown ? 2.5 : 1.5} />
          </button>
          <div className="w-px h-5 bg-stone-300 dark:bg-stone-700"></div>
          <button className="p-2 text-stone-400 dark:text-stone-500 hover:text-stone-600 transition-colors active:scale-95">
            <Share2 size={20} strokeWidth={1.5} />
          </button>
          <div className="w-px h-5 bg-stone-300 dark:bg-stone-700"></div>
          <button 
             onClick={() => setShowPlaylistSelector(true)}
             className="p-2 text-stone-400 dark:text-stone-500 hover:text-stone-600 transition-colors active:scale-95"
          >
            <ListMusic size={20} strokeWidth={1.5} />
          </button>
        </div>
      </div>
    </div>
  );
};

