      </main>

      {/* Mini Player - Floating Glass Pill */}
      {currentTrack && !isFullPlayerOpen && (
        <div 
          onClick={() => setIsFullPlayerOpen(true)}
          className="fixed bottom-[100px] left-6 right-6 h-16 glass-card rounded-full flex items-center justify-between cursor-pointer z-40 transition-all hover:-translate-y-1 active:scale-[0.98] pr-3 pl-2"
