import { Track, User } from '../types';

const DB_NAME = 'ArbNoorDB';
const TRACKS_STORE = 'tracks';
const USERS_STORE = 'users';
const DB_VERSION = 2; // Incremented for User store

// Initialize IndexedDB
export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;

      // Create Tracks Store
      if (!db.objectStoreNames.contains(TRACKS_STORE)) {
        db.createObjectStore(TRACKS_STORE, { keyPath: 'id' });
      }

      // Create Users Store
      if (!db.objectStoreNames.contains(USERS_STORE)) {
        const userStore = db.createObjectStore(USERS_STORE, { keyPath: 'id' });
        // Create index on email for login lookup
        userStore.createIndex('email', 'email', { unique: true });
      }
    };
  });
};

// --- TRACKS OPERATIONS ---

// Save a track (including File objects) to DB
export const saveTrackToDB = async (track: Track) => {
  const db = await initDB();
  return new Promise<void>((resolve, reject) => {
    const transaction = db.transaction([TRACKS_STORE], 'readwrite');
    const store = transaction.objectStore(TRACKS_STORE);
    const request = store.put(track); 

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

// Retrieve all tracks and regenerate Blob URLs
export const getTracksFromDB = async (): Promise<Track[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([TRACKS_STORE], 'readonly');
    const store = transaction.objectStore(TRACKS_STORE);
    const request = store.getAll();

    request.onsuccess = () => {
        const tracks = request.result as Track[];
        // Revive blob URLs for playback
        const hydratedTracks = tracks.map(t => {
            // If we have stored files, create new URLs for this session
            const audioUrl = t.localAudioFile ? URL.createObjectURL(t.localAudioFile) : t.url;
            const imageUrl = t.localImageFile ? URL.createObjectURL(t.localImageFile) : t.coverUrl;

            return {
                ...t,
                url: audioUrl,
                coverUrl: imageUrl
            };
        });
        resolve(hydratedTracks);
    };
    request.onerror = () => reject(request.error);
  });
};

// Delete a track from DB
export const deleteTrackFromDB = async (id: string) => {
    const db = await initDB();
    return new Promise<void>((resolve, reject) => {
        const transaction = db.transaction([TRACKS_STORE], 'readwrite');
        const store = transaction.objectStore(TRACKS_STORE);
        const request = store.delete(id);
        request.onsuccess = () => resolve();
        request.onerror = () => reject(request.error);
    });
};

// --- USER OPERATIONS ---

export const registerUserInDB = async (user: User): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([USERS_STORE], 'readwrite');
    const store = transaction.objectStore(USERS_STORE);

    // Check if email exists via index
    const emailIndex = store.index('email');
    const checkRequest = emailIndex.get(user.email);

    checkRequest.onsuccess = () => {
      if (checkRequest.result) {
        reject(new Error("Email already registered"));
      } else {
        const addRequest = store.add(user);
        addRequest.onsuccess = () => resolve();
        addRequest.onerror = () => reject(addRequest.error);
      }
    };
    checkRequest.onerror = () => reject(checkRequest.error);
  });
};

export const getUserFromDB = async (email: string): Promise<User | undefined> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([USERS_STORE], 'readonly');
    const store = transaction.objectStore(USERS_STORE);
    const index = store.index('email');
    const request = index.get(email);

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const getUserByIdFromDB = async (id: string): Promise<User | undefined> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction([USERS_STORE], 'readonly');
    const store = transaction.objectStore(USERS_STORE);
    const request = store.get(id);

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User } from '../types';
import { getUserFromDB, registerUserInDB, getUserByIdFromDB } from '../utils/storage';

interface AuthContextType {
  user: User | null;
  isAdmin: boolean; 
  login: (email: string, pass: string) => Promise<boolean>;
  signup: (email: string, pass: string, name: string) => Promise<boolean>;
  logout: () => void;
  switchRole: () => void;
  authError: string | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [authError, setAuthError] = useState<string | null>(null);
  const [loadingSession, setLoadingSession] = useState(true);

  // Restore Session on App Load
  useEffect(() => {
    const restoreSession = async () => {
      const storedUserId = localStorage.getItem('arbnoor_session_uid');
      if (storedUserId) {
        try {
          const dbUser = await getUserByIdFromDB(storedUserId);
          if (dbUser) {
            setUser(dbUser);
          } else {
            // Invalid session
            localStorage.removeItem('arbnoor_session_uid');
            setGuestUser();
          }
        } catch (e) {
          console.error("Session restore failed", e);
          setGuestUser();
        }
      } else {
        setGuestUser();
      }
      setLoadingSession(false);
    };

    restoreSession();
  }, []);

  const setGuestUser = () => {
    setUser({
      id: 'guest',
      email: '',
      role: 'user',
      name: 'Listener'
    });
  };

  const login = async (email: string, pass: string): Promise<boolean> => {
    setAuthError(null);
    try {
      const dbUser = await getUserFromDB(email);

      if (!dbUser) {
        setAuthError("Account not found.");
        return false;
      }

      if (dbUser.password !== pass) {
        setAuthError("Incorrect password.");
        return false;
      }

      // Success
      setUser(dbUser);
      localStorage.setItem('arbnoor_session_uid', dbUser.id);
      return true;

    } catch (e) {
      console.error(e);
      setAuthError("Login failed due to database error.");
      return false;
    }
  };

  const signup = async (email: string, pass: string, name: string): Promise<boolean> => {
    setAuthError(null);
    try {
      const newUser: User = {
        id: crypto.randomUUID(), // Unique ID
        email,
        password: pass,
        name: name || 'Publisher',
        role: 'publisher',
        createdAt: Date.now()
      };

      await registerUserInDB(newUser);

      // Auto Login
      setUser(newUser);
      localStorage.setItem('arbnoor_session_uid', newUser.id);
      return true;

    } catch (e: any) {
      if (e.message === "Email already registered") {
        setAuthError("An account with this email already exists.");
      } else {
        setAuthError("Registration failed. Please try again.");
      }
      return false;
    }
  };

  const logout = () => {
    localStorage.removeItem('arbnoor_session_uid');
    setGuestUser();
  };

  const switchRole = () => {
    if (user) {
        setUser({
            ...user,
            role: user.role === 'publisher' ? 'user' : 'publisher'
        });
    }
  };

  const isAdmin = user?.role === 'publisher';

  return (
    <AuthContext.Provider value={{ user, isAdmin, login, signup, logout, switchRole, authError }}>
      {!loadingSession && children}
    </AuthContext.Provider>
  );
};

