              </div>


              <div className="bg-teal-50/50 dark:bg-teal-900/20 border border-teal-100/50 dark:border-teal-800/50 rounded-3xl p-5">
                <label className="flex items-start gap-3 cursor-pointer">
                  <div className={`mt-0.5 w-5 h-5 rounded border flex items-center justify-center flex-shrink-0 transition-all ${isVocalsVerified ? 'bg-teal-600 border-teal-600' : 'border-stone-300 dark:border-slate-600 bg-white dark:bg-slate-700'}`}>
