import React from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import Layout from './components/Layout';
import Home from './pages/Home';
import Search from './pages/Search';
import Library from './pages/Library';
import Account from './pages/Account';
import Auth from './pages/Auth';
import AdminDashboard from './pages/AdminDashboard';
import { AudioProvider } from './context/AudioContext';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';
import { Loader } from 'lucide-react';

// Protected Route Wrapper
const RequireAuth = ({ children }: { children: React.ReactElement }) => {
  const { user, loadingSession } = useAuth();
  const location = useLocation();

  if (loadingSession) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#F7F5F0] dark:bg-[#1C1917]">
        <Loader className="animate-spin text-stone-400" size={32} />
      </div>
    );
  }

  if (!user) {
    // Redirect them to the /auth page, but save the current location they were
    // trying to go to when they were redirected.
    return <Navigate to="/auth" state={{ from: location }} replace />;
  }

  return children;
};

const AppRoutes = () => {
  const { user, isAdmin } = useAuth();

  return (
    <Routes>
      {/* Public Auth Route */}
      <Route 
        path="/auth" 
        element={user ? <Navigate to="/" replace /> : <Auth />} 
      />

      {/* Admin/Publisher Routes */}
      <Route 
        path="/admin/dashboard" 
        element={
          <RequireAuth>
             {isAdmin ? <AdminDashboard /> : <Navigate to="/" replace />} 
          </RequireAuth>
        } 
      />

      {/* User Routes (Protected) */}
      <Route element={
        <RequireAuth>
          <Layout />
        </RequireAuth>
      }>
        <Route path="/" element={<Home />} />
        <Route path="/search" element={<Search />} />
        <Route path="/library" element={<Library />} />
        <Route path="/account" element={<Account />} />
        <Route path="/settings" element={<Navigate to="/account" replace />} />
      </Route>

      {/* Catch-all redirect */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

const App = () => {
  return (
    <ThemeProvider>
      <AuthProvider>
        <AudioProvider>
          <HashRouter>
            <AppRoutes />
          </HashRouter>
        </AudioProvider>
      </AuthProvider>
    </ThemeProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { ShieldCheck, Lock, Mail, AlertCircle, ArrowLeft, UserPlus, LogIn, User } from 'lucide-react';

const AdminLogin = () => {
  const [isSignUp, setIsSignUp] = useState(false);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');

  const [formError, setFormError] = useState('');
  const { login, signup, authError } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError('');

    if (isSignUp) {
      if (password.length < 6) {
        setFormError("Password must be at least 6 characters.");
        return;
      }
      if (password !== confirmPassword) {
        setFormError("Passwords do not match.");
        return;
      }

      const success = await signup(email, password, name, 'publisher');
      if (success) navigate('/admin/dashboard');

    } else {
      const success = await login(email, password);
      if (success) navigate('/admin/dashboard');
    }
  };

  const toggleMode = () => {
    setIsSignUp(!isSignUp);
    setFormError('');
    setEmail('');
    setPassword('');
    setConfirmPassword('');
    setName('');
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 pattern-bg relative">

      {/* Back Button */}
      <button onClick={() => navigate('/settings')} className="absolute top-6 left-6 p-3 glass-card rounded-full text-stone-600 hover:bg-white/80 transition-colors shadow-sm z-20">
        <ArrowLeft size={24} />
      </button>

      <div className="w-full max-w-sm relative z-10">
        <div className="flex flex-col items-center mb-8">
          <div className="w-24 h-24 glass-card rounded-[2rem] flex items-center justify-center mb-6 shadow-lg rotate-3 border border-white/60">
            <ShieldCheck size={48} className="text-charcoal-800 dark:text-white" strokeWidth={1} />
          </div>
          <h1 className="text-4xl font-serif font-bold text-charcoal-900 dark:text-white text-center">
            {isSignUp ? 'Publisher Sign Up' : 'Publisher Login'}
          </h1>
          <p className="text-xs text-stone-500 dark:text-stone-400 mt-3 font-bold tracking-widest uppercase">
            {isSignUp ? 'Create your workspace' : 'Content Management'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="glass-card p-8 rounded-[2.5rem] shadow-2xl shadow-charcoal-900/5 dark:shadow-black/30 space-y-5 relative overflow-hidden bg-cream-50/60 dark:bg-stone-800/60">

          {(formError || authError) && (
            <div className="bg-red-50/90 text-red-600 px-4 py-4 rounded-2xl text-xs font-bold flex items-center gap-3 border border-red-100">
              <AlertCircle size={18} />
              {formError || authError}
            </div>
          )}

          {isSignUp && (
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-4">Full Name</label>
              <div className="relative group">
                <User className="absolute left-6 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                <input
                  type="text"
                  required
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="relative w-full bg-white/60 dark:bg-black/20 border border-white/50 dark:border-stone-700 text-charcoal-900 dark:text-white pl-14 pr-6 py-4 rounded-[1.5rem] focus:outline-none focus:bg-white/80 focus:border-stone-300 transition-all placeholder:text-stone-300 font-medium text-sm"
                  placeholder="Publisher Name"
                />
              </div>
            </div>
          )}

          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-4">Email Address</label>
            <div className="relative group">
              <Mail className="absolute left-6 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="relative w-full bg-white/60 dark:bg-black/20 border border-white/50 dark:border-stone-700 text-charcoal-900 dark:text-white pl-14 pr-6 py-4 rounded-[1.5rem] focus:outline-none focus:bg-white/80 focus:border-stone-300 transition-all placeholder:text-stone-300 font-medium text-sm"
                placeholder="publisher@arbnoor.com"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-4">Password</label>
            <div className="relative group">
              <Lock className="absolute left-6 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
              <input
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="relative w-full bg-white/60 dark:bg-black/20 border border-white/50 dark:border-stone-700 text-charcoal-900 dark:text-white pl-14 pr-6 py-4 rounded-[1.5rem] focus:outline-none focus:bg-white/80 focus:border-stone-300 transition-all placeholder:text-stone-300 font-medium text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          {isSignUp && (
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-stone-400 uppercase tracking-widest ml-4">Confirm Password</label>
              <div className="relative group">
                <Lock className="absolute left-6 top-1/2 -translate-y-1/2 text-stone-400" size={18} />
                <input
                  type="password"
                  required
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="relative w-full bg-white/60 dark:bg-black/20 border border-white/50 dark:border-stone-700 text-charcoal-900 dark:text-white pl-14 pr-6 py-4 rounded-[1.5rem] focus:outline-none focus:bg-white/80 focus:border-stone-300 transition-all placeholder:text-stone-300 font-medium text-sm"
                  placeholder="••••••••"
                />
              </div>
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-charcoal-800 dark:bg-white hover:bg-charcoal-900 dark:hover:bg-stone-200 text-cream-50 dark:text-charcoal-900 font-bold py-5 rounded-[1.5rem] transition-all shadow-lg active:scale-95 mt-4 text-sm tracking-wide uppercase flex items-center justify-center gap-2"
          >
            {isSignUp ? (
              <><UserPlus size={18} /> Create Account</>
            ) : (
              <><LogIn size={18} /> Login</>
            )}
          </button>
        </form>

        <div className="mt-8 text-center">
            <p className="text-xs text-stone-500 font-medium">
                {isSignUp ? "Already have an account?" : "Don't have an account?"}
            </p>
            <button 
                onClick={toggleMode}
                className="mt-2 text-charcoal-800 dark:text-white font-bold uppercase tracking-wide text-xs hover:underline decoration-teal-500 decoration-2 underline-offset-4"
            >
                {isSignUp ? "Login Here" : "Create Publisher Account"}
            </button>
        </div>
      </div>
    </div>
  );
};

