        </div>
      )}
    </div>
  );
};

export default Home;

import React, { useState, useMemo } from 'react';
import { Search as SearchIcon, XCircle, CheckCircle2 } from 'lucide-react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';

const Search = () => {
  const [query, setQuery] = useState('');
  const { playTrack, currentTrack, tracks, isDownloaded } = useAudio();

  const filteredTracks = useMemo(() => {
    if (!query) return [];
    return tracks.filter(t => 
      t.title.toLowerCase().includes(query.toLowerCase()) || 
      t.artist.toLowerCase().includes(query.toLowerCase())
    );
  }, [query, tracks]);

  return (
    <div className="p-6 min-h-full pb-32">
      <h1 className="text-3xl font-bold mb-6 text-stone-800 font-serif">Search</h1>

      {/* Search Bar */}
      <div className="relative mb-8 group">
        <div className="absolute inset-0 bg-teal-500/5 rounded-3xl blur-xl transition-opacity opacity-0 group-focus-within:opacity-100"></div>
        <SearchIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-stone-400" size={20} />
        <input 
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Naat, Reciter, Nasheed..."
          className="relative w-full bg-white/60 backdrop-blur-xl border border-white/60 text-stone-800 pl-14 pr-12 py-5 rounded-3xl focus:outline-none focus:ring-2 focus:ring-teal-500/10 focus:border-teal-400 transition-all placeholder:text-stone-400 shadow-sm"
        />
        {query && (
          <button 
            onClick={() => setQuery('')}
            className="absolute right-5 top-1/2 -translate-y-1/2 text-stone-400 hover:text-stone-600 z-10"
          >
            <XCircle size={20} fill="currentColor" className="text-stone-200" />
          </button>
        )}
      </div>

      {/* Results or Empty State */}
      <div className="space-y-3">
        {query.length > 0 ? (
          filteredTracks.length > 0 ? (
            filteredTracks.map(track => (
              <SearchItem 
                key={track.id} 
                track={track} 
                onClick={() => playTrack(track)} 
                active={currentTrack?.id === track.id} 
                downloaded={isDownloaded(track.id)}
              />
            ))
          ) : (
            <div className="text-center py-10 text-stone-400">
              <p>No results found for "{query}"</p>
            </div>
          )
        ) : (
          <div>
            <h3 className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-4 px-2">Browse All Content</h3>
            <div className="bg-white/30 backdrop-blur-md rounded-[2rem] p-3 border border-white/50 shadow-sm">
              {tracks.map(track => (
                <SearchItem 
                    key={track.id} 
                    track={track} 
                    onClick={() => playTrack(track)} 
                    active={currentTrack?.id === track.id}
                    downloaded={isDownloaded(track.id)}
                />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const SearchItem: React.FC<{ 
    track: Track, 
    onClick: () => void, 
    active: boolean, 
    downloaded: boolean 
}> = ({ track, onClick, active, downloaded }) => (
  <div onClick={onClick} className={`flex items-center gap-4 p-3 rounded-2xl cursor-pointer transition-all ${active ? 'bg-white/80 shadow-md ring-1 ring-teal-100' : 'hover:bg-white/40'}`}>
    <img src={track.coverUrl} className="w-14 h-14 rounded-2xl bg-stone-100 object-cover shadow-sm border border-white/30" alt="" />
    <div className="flex-1 min-w-0">
      <div className="flex items-center gap-1.5">
          <h4 className={`text-sm font-bold truncate ${active ? 'text-teal-900' : 'text-stone-800'}`}>{track.title}</h4>
          {downloaded && (
             <CheckCircle2 size={12} className="text-teal-600 flex-shrink-0" fill="currentColor" stroke="white" />
          )}
      </div>
      <p className="text-xs text-stone-500 flex items-center gap-1.5 mt-1">
        {track.artist}
        {track.isVocalsOnly && <span className="text-[9px] bg-teal-50 text-teal-600 px-1.5 py-0.5 rounded border border-teal-100/50">VOCALS</span>}
      </p>
    </div>
  </div>
);

export default Search;

import React, { useState } from 'react';
import { useAudio } from '../context/AudioContext';
import { Track } from '../types';
import { Heart, Download, Music, ListMusic, Plus, ChevronLeft, Trash2, CheckCircle2 } from 'lucide-react';

type Tab = 'favorites' | 'downloads' | 'playlists';

const Library = () => {
  const [activeTab, setActiveTab] = useState<Tab>('favorites');
  const [viewingPlaylistId, setViewingPlaylistId] = useState<string | null>(null);

  const { 
    favorites, 
    isDownloaded,
    toggleDownload, 
    playlists, 
    createPlaylist, 
    deletePlaylist, 
    removeTrackFromPlaylist, 
    playTrack, 
    currentTrack, 
    tracks 
  } = useAudio();

  // Helper to get tracks
  const getTracksByIds = (ids: string[]) => tracks.filter(t => ids.includes(t.id));

  const favoriteTracks = getTracksByIds(favorites);
  const downloadedTracks = tracks.filter(t => isDownloaded(t.id));

  const viewingPlaylist = viewingPlaylistId ? playlists.find(p => p.id === viewingPlaylistId) : null;
  const playlistTracks = viewingPlaylist ? getTracksByIds(viewingPlaylist.trackIds) : [];

  const handleCreatePlaylist = () => {
    const name = prompt("Enter playlist name:");
    if (name && name.trim()) {
      createPlaylist(name.trim());
    }
  };

  const handleDeletePlaylist = () => {
    if (viewingPlaylist && confirm(`Are you sure you want to delete "${viewingPlaylist.name}"?`)) {
      deletePlaylist(viewingPlaylist.id);
      setViewingPlaylistId(null);
    }
  };

  // If viewing a specific playlist, show detail view
  if (viewingPlaylistId && viewingPlaylist) {
    return (
      <div className="p-6 min-h-full pb-32">
        <button 
          onClick={() => setViewingPlaylistId(null)} 
          className="flex items-center gap-2 text-stone-500 hover:text-stone-800 mb-6 transition-colors"
        >
          <ChevronLeft size={20} /> Back
        </button>

        <div className="flex justify-between items-start mb-6">
           <div>
             <h1 className="text-3xl font-bold text-stone-800 dark:text-white font-serif">{viewingPlaylist.name}</h1>
             <p className="text-sm text-stone-500 dark:text-stone-400 mt-1">{playlistTracks.length} Tracks</p>
           </div>
           <button 
             onClick={handleDeletePlaylist}
             className="p-3 bg-red-50 dark:bg-red-900/20 text-red-500 rounded-full hover:bg-red-100 dark:hover:bg-red-900/40 transition-colors"
           >
             <Trash2 size={20} />
           </button>
        </div>

        <div className="space-y-3">
          {playlistTracks.length > 0 ? (
            playlistTracks.map(track => (
              <LibraryItem 
                key={track.id} 
                track={track} 
                onClick={() => playTrack(track)} 
                isActive={currentTrack?.id === track.id}
                downloaded={isDownloaded(track.id)}
                onRemove={(e) => {
                  e.stopPropagation();
                  removeTrackFromPlaylist(viewingPlaylist.id, track.id);
                }}
              />
            ))
          ) : (
            <div className="text-center py-20 text-stone-400">
              <Music size={48} className="mx-auto mb-4 opacity-50" />
              <p>This playlist is empty.</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // Default Library View
  return (
    <div className="p-6 min-h-full pb-32">
      <h1 className="text-3xl font-bold mb-8 text-stone-800 dark:text-white font-serif">Your Library</h1>

      {/* Tabs */}
      <div className="flex p-1 bg-white/40 dark:bg-slate-800/40 backdrop-blur-xl border border-white/50 dark:border-slate-700 rounded-full mb-8 relative shadow-inner">
        {(['favorites', 'downloads', 'playlists'] as Tab[]).map((tab) => (
           <button 
           key={tab}
           onClick={() => setActiveTab(tab)}
           className={`flex-1 py-3 text-xs sm:text-sm font-bold rounded-full transition-all capitalize ${activeTab === tab ? 'bg-white dark:bg-slate-700 text-teal-900 dark:text-white shadow-md' : 'text-stone-500 dark:text-stone-400 hover:text-stone-700 dark:hover:text-stone-200'}`}
         >
           {tab}
         </button>
        ))}
      </div>

      {/* Content */}
      <div className="space-y-3">
        {activeTab === 'playlists' ? (
          <>
            <button 
              onClick={handleCreatePlaylist}
              className="w-full py-4 border-2 border-dashed border-stone-300 dark:border-slate-600 rounded-3xl text-stone-500 dark:text-stone-400 font-bold flex items-center justify-center gap-2 hover:bg-white/40 dark:hover:bg-slate-800/40 transition-colors mb-4"
            >
              <Plus size={20} /> Create New Playlist
            </button>

            {playlists.length > 0 ? (
              playlists.map(playlist => (
                <div 
                  key={playlist.id}
                  onClick={() => setViewingPlaylistId(playlist.id)}
                  className="flex items-center gap-4 p-4 rounded-3xl bg-white/40 dark:bg-slate-800/40 border border-white/50 dark:border-slate-700 cursor-pointer hover:bg-white/60 dark:hover:bg-slate-800/60 transition-colors"
                >
                  <div className="w-16 h-16 rounded-2xl bg-teal-50 dark:bg-teal-900/30 flex items-center justify-center text-teal-600 dark:text-teal-400 border border-teal-100 dark:border-teal-800">
                    <ListMusic size={24} />
                  </div>
                  <div className="flex-1">
                    <h4 className="font-bold text-stone-800 dark:text-white">{playlist.name}</h4>
                    <p className="text-xs text-stone-500 dark:text-stone-400 mt-1">{playlist.trackIds.length} Tracks</p>
                  </div>
                  <ChevronLeft size={20} className="rotate-180 text-stone-400" />
                </div>
              ))
            ) : null}
          </>
        ) : (
          (activeTab === 'favorites' ? favoriteTracks : downloadedTracks).length > 0 ? (
            (activeTab === 'favorites' ? favoriteTracks : downloadedTracks).map(track => (
              <LibraryItem 
                key={track.id} 
                track={track} 
                onClick={() => playTrack(track)} 
                isActive={currentTrack?.id === track.id}
                downloaded={isDownloaded(track.id)}
                // Allow removing downloads if we are in the Downloads tab
                onRemove={activeTab === 'downloads' ? (e) => {
                  e.stopPropagation();
                  toggleDownload(track.id);
                } : undefined}
              />
            ))
          ) : (
            <EmptyState type={activeTab} />
          )
        )}
      </div>
    </div>
  );
};

const LibraryItem: React.FC<{ 
  track: Track, 
  onClick: () => void, 
  isActive: boolean,
  downloaded: boolean, 
  onRemove?: (e: React.MouseEvent) => void 
}> = ({ 
  track, 
  onClick, 
  isActive,
  downloaded, 
  onRemove 
}) => (
  <div 
    onClick={onClick}
    className={`flex items-center gap-4 p-3 rounded-3xl transition-all cursor-pointer border ${isActive ? 'bg-white/80 dark:bg-slate-700 border-teal-100 dark:border-teal-900 shadow-md' : 'bg-white/30 dark:bg-slate-800/30 border-transparent hover:bg-white/50 dark:hover:bg-slate-800/50 hover:border-white/40'}`}
  >
    <div className="w-14 h-14 rounded-2xl overflow-hidden bg-stone-100 dark:bg-slate-900 shadow-sm border border-white/30 dark:border-slate-700">
      <img src={track.coverUrl} alt="" className="w-full h-full object-cover" />
    </div>
    <div className="flex-1 min-w-0">
      <div className="flex items-center gap-1.5">
          <h4 className={`text-sm font-bold truncate ${isActive ? 'text-teal-900 dark:text-teal-400' : 'text-stone-800 dark:text-white'}`}>{track.title}</h4>
          {downloaded && (
             <CheckCircle2 size={12} className="text-teal-600 dark:text-teal-400 flex-shrink-0" fill="currentColor" stroke="white" />
          )}
      </div>
      <p className="text-xs text-stone-500 dark:text-stone-400 mt-1">{track.artist}</p>
    </div>

    {/* If active, show Playing Icon. If remove allowed, show Trash. Otherwise show nothing (or just arrow if desired, but kept clean) */}
    {isActive ? (
      <div className="w-8 h-8 rounded-full bg-teal-50 dark:bg-teal-900/50 flex items-center justify-center">
        <Music size={16} className="text-teal-600 dark:text-teal-400" />
      </div>
    ) : onRemove ? (
      <button 
        onClick={onRemove} 
        className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-red-50 dark:hover:bg-red-900/30 text-stone-400 hover:text-red-500 transition-colors"
      >
        <Trash2 size={18} />
      </button>
    ) : null}
  </div>
);

const EmptyState = ({ type }: { type: Tab }) => (
  <div className="flex flex-col items-center justify-center py-20 text-stone-400">
    <div className="w-24 h-24 rounded-full bg-white/40 dark:bg-slate-800/40 border border-white/60 dark:border-slate-700 flex items-center justify-center mb-6 shadow-sm backdrop-blur-sm">
      {type === 'favorites' ? <Heart size={36} className="text-stone-300 dark:text-stone-500" /> : <Download size={36} className="text-stone-300 dark:text-stone-500" />}
    </div>
    <p className="text-lg font-serif font-bold text-stone-600 dark:text-stone-300 capitalize">No {type} yet</p>
    <p className="text-sm mt-2 text-stone-400">Start listening to build your collection.</p>
  </div>
);

export default Library;

import React, { useState, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useAudio } from '../context/AudioContext';
import { useNavigate } from 'react-router-dom';
import { ShieldCheck, Plus, Trash2, LogOut, Play, Square, CheckCircle, Upload, Image as ImageIcon, Music, ArrowLeft } from 'lucide-react';
import { Category, Track } from '../types';

const AdminDashboard = () => {
  const { user } = useAuth();
  const { tracks, addTrack, deleteTrack } = useAudio();
  const navigate = useNavigate();

  // Filter tracks to show only those owned by this publisher
  const myTracks = tracks.filter(t => t.publisherId === user?.id);

  // Form State
  const [title, setTitle] = useState('');
  const [artist, setArtist] = useState('');
  const [category, setCategory] = useState<Category>(Category.NAAT);

  // File State
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [imageFile, setImageFile] = useState<File | null>(null);

  // Previews
  const [audioPreviewUrl, setAudioPreviewUrl] = useState<string>('');
  const [imagePreviewUrl, setImagePreviewUrl] = useState<string>('');

  const [isVocalsVerified, setIsVocalsVerified] = useState(false);
  const [previewAudio, setPreviewAudio] = useState<HTMLAudioElement | null>(null);
  const [isPreviewPlaying, setIsPreviewPlaying] = useState(false);

  // File Refs
  const audioInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  const handleExit = () => {
    if (previewAudio) {
      previewAudio.pause();
    }
    // Do not logout, just navigate back to the main app
    navigate('/account');
  };

  const handleAudioFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      if (file.type !== 'audio/mpeg' && file.type !== 'audio/mp3') {
        alert("Please upload a valid MP3 file.");
        return;
      }
      setAudioFile(file);
      // Create object URL for preview
      const url = URL.createObjectURL(file);
      setAudioPreviewUrl(url);
    }
  };

  const handleImageFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      const url = URL.createObjectURL(file);
      setImagePreviewUrl(url);
    }
  };

  const handlePreview = () => {
    if (isPreviewPlaying && previewAudio) {
      previewAudio.pause();
      setIsPreviewPlaying(false);
    } else {
      if (!audioPreviewUrl) return;
      const audio = new Audio(audioPreviewUrl);
      audio.onended = () => setIsPreviewPlaying(false);
      audio.play().catch(e => alert("Could not play audio."));
      setPreviewAudio(audio);
      setIsPreviewPlaying(true);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!user) {
        alert("You must be logged in to publish.");
        return;
    }

    if (!isVocalsVerified) {
      alert("You must verify that the content is Vocals Only.");
      return;
    }
    if (!audioFile || !imageFile) {
        alert("Both audio and thumbnail files are mandatory.");
        return;
    }

    const newTrack: Track = {
      id: Date.now().toString(),
      title,
      artist,
      category,
      url: audioPreviewUrl, 
      coverUrl: imagePreviewUrl,
      duration: 0, 
      isVocalsOnly: true,
      localAudioFile: audioFile,
      localImageFile: imageFile,
      publisherId: user.id // Tag with current user ID
    };

    addTrack(newTrack);

    // Reset form
    setTitle('');
    setArtist('');
    setAudioFile(null);
    setImageFile(null);
    setAudioPreviewUrl('');
    setImagePreviewUrl('');
    setIsVocalsVerified(false);
    if(audioInputRef.current) audioInputRef.current.value = '';
    if(imageInputRef.current) imageInputRef.current.value = '';

    alert("Track published successfully!");
  };

  return (
    <div className="min-h-screen text-stone-800 dark:text-stone-200 font-sans pb-20 transition-colors duration-300">
      {/* Navbar - Glass */}
      <div className="bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border-b border-white/50 dark:border-slate-700 p-4 flex justify-between items-center sticky top-0 z-20 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 bg-teal-50/80 dark:bg-teal-900/50 rounded-xl flex items-center justify-center border border-teal-100/50 dark:border-teal-800 shadow-sm">
             <ShieldCheck size={20} className="text-teal-700 dark:text-teal-400" />
          </div>
          <div>
            <h1 className="font-bold text-stone-800 dark:text-white font-serif text-xl leading-none">Publisher</h1>
            <div className="flex items-center gap-1.5 text-[9px] tracking-wider text-teal-700 dark:text-teal-400 font-bold uppercase mt-1">
              <span className="w-1.5 h-1.5 bg-teal-500 rounded-full animate-pulse"></span>
              {user?.name || 'Authorized'}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={handleExit} className="text-xs font-bold text-stone-500 dark:text-stone-400 hover:text-stone-800 dark:hover:text-stone-200 flex items-center gap-2 bg-white/60 dark:bg-slate-800/60 hover:bg-stone-50 dark:hover:bg-slate-700 px-4 py-2.5 rounded-xl transition-colors border border-white/60 dark:border-slate-700 shadow-sm">
             <ArrowLeft size={14} /> <span className="hidden sm:inline">Back to App</span>
           </button>
        </div>
      </div>

      <div className="p-6 max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Upload Form */}
        <div className="lg:col-span-1">
          <div className="bg-white/60 dark:bg-slate-800/60 backdrop-blur-2xl rounded-[2.5rem] border border-white/60 dark:border-slate-700 p-8 shadow-xl shadow-stone-200/20 dark:shadow-none sticky top-28">
            <h2 className="text-xl font-bold text-stone-800 dark:text-white mb-8 flex items-center gap-3">
              <span className="w-10 h-10 rounded-2xl bg-amber-100/80 dark:bg-amber-900/50 text-amber-700 dark:text-amber-400 flex items-center justify-center border border-amber-200/50 dark:border-amber-800"><Plus size={22} /></span>
              Upload Content
            </h2>

            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Metadata */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Title</label>
                <input required value={title} onChange={e => setTitle(e.target.value)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium dark:text-white" placeholder="e.g. Maula Ya Salli" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Reciter / Artist</label>
                <input required value={artist} onChange={e => setArtist(e.target.value)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium dark:text-white" placeholder="e.g. Junaid Jamshed" />
              </div>

              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Category</label>
                <div className="relative">
                    <select value={category} onChange={e => setCategory(e.target.value as Category)} className="w-full bg-white/80 dark:bg-slate-900/50 border border-stone-100 dark:border-slate-600 rounded-2xl p-4 text-sm focus:border-teal-400 focus:ring-4 focus:ring-teal-400/10 outline-none transition-all shadow-sm font-medium appearance-none dark:text-white">
                    {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                    </select>
                </div>
              </div>

              {/* Audio Upload */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Audio File (MP3)</label>
                <div className={`border-2 border-dashed rounded-2xl p-4 flex flex-col items-center justify-center text-center transition-colors ${audioFile ? 'border-teal-400 bg-teal-50/50 dark:bg-teal-900/20' : 'border-stone-200 dark:border-slate-600 hover:border-teal-300'}`}>
                    <input 
                        type="file" 
                        accept="audio/mp3,audio/mpeg" 
                        ref={audioInputRef}
                        onChange={handleAudioFileChange}
                        className="hidden" 
                        id="audio-upload"
                    />
                    <label htmlFor="audio-upload" className="cursor-pointer w-full flex flex-col items-center">
                        {audioFile ? (
                            <>
                                <Music size={24} className="text-teal-600 mb-2" />
                                <span className="text-xs font-bold text-teal-800 dark:text-teal-300 truncate w-full">{audioFile.name}</span>
                                <button type="button" onClick={handlePreview} className="mt-2 text-[10px] bg-white dark:bg-slate-700 border border-stone-200 dark:border-slate-600 px-3 py-1 rounded-full font-bold flex items-center gap-1 shadow-sm">
                                    {isPreviewPlaying ? <Square size={10} className="text-red-500" fill="currentColor"/> : <Play size={10} className="text-teal-600" fill="currentColor"/>}
                                    Preview
                                </button>
                            </>
                        ) : (
                            <>
                                <Upload size={24} className="text-stone-300 mb-2" />
                                <span className="text-xs font-bold text-stone-500">Click to upload MP3</span>
                            </>
                        )}
                    </label>
                </div>
              </div>

              {/* Thumbnail Upload */}
              <div>
                <label className="block text-xs font-bold text-stone-400 uppercase mb-2 ml-1 tracking-wider">Thumbnail Image</label>
                <div className={`border-2 border-dashed rounded-2xl p-4 flex flex-col items-center justify-center text-center transition-colors relative overflow-hidden ${imageFile ? 'border-teal-400' : 'border-stone-200 dark:border-slate-600 hover:border-teal-300'}`}>
                    <input 
                        type="file" 
                        accept="image/*" 
                        ref={imageInputRef}
                        onChange={handleImageFileChange}
                        className="hidden" 
                        id="image-upload"
                    />
                    <label htmlFor="image-upload" className="cursor-pointer w-full flex flex-col items-center relative z-10">
                         {imageFile ? (
                             <>
