import React from 'react';
// @ts-ignore
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import Layout from './components/Layout';
import Home from './pages/Home';
import Search from './pages/Search';
import Library from './pages/Library';
import Account from './pages/Account';
import Auth from './pages/Auth';
import AdminDashboard from './pages/AdminDashboard';
import { AudioProvider } from './context/AudioContext';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';
import { Loader } from 'lucide-react';

// Protected Route Wrapper
const RequireAuth = ({ children }: { children: React.ReactElement }) => {
  const { user, loadingSession } = useAuth();
  const location = useLocation();

  if (loadingSession) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#F7F5F0] dark:bg-[#1C1917]">
        <Loader className="animate-spin text-stone-400" size={32} />
      </div>
    );
  }

  if (!user) {
    // Redirect them to the /auth page, but save the current location they were
    // trying to go to when they were redirected.
    return <Navigate to="/auth" state={{ from: location }} replace />;
  }

  return children;
};

const AppRoutes = () => {
  const { user, isAdmin } = useAuth();

  return (
    <Routes>
      {/* Public Auth Route */}
      <Route 
        path="/auth" 
        element={user ? <Navigate to="/" replace /> : <Auth />} 
      />

      {/* Admin/Publisher Routes */}
      <Route 
        path="/admin/dashboard" 
        element={
          <RequireAuth>
             {isAdmin ? <AdminDashboard /> : <Navigate to="/" replace />} 
          </RequireAuth>
        } 
      />

      {/* User Routes (Protected) */}
      <Route element={
        <RequireAuth>
          <Layout />
        </RequireAuth>
      }>
        <Route path="/" element={<Home />} />
        <Route path="/search" element={<Search />} />
        <Route path="/library" element={<Library />} />
        <Route path="/account" element={<Account />} />
        <Route path="/settings" element={<Navigate to="/account" replace />} />
      </Route>

      {/* Catch-all redirect */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

const App = () => {
  return (
    <ThemeProvider>
      <AuthProvider>
        <AudioProvider>
          <HashRouter>
            <AppRoutes />
          </HashRouter>
        </AudioProvider>
      </AuthProvider>
    </ThemeProvider>
  );
};

export default App;

import React, { useState } from 'react';
// @ts-ignore
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { ShieldCheck, Lock, Mail, AlertCircle, ArrowLeft, UserPlus, LogIn, User } from 'lucide-react';

const AdminLogin = () => {
  const [isSignUp, setIsSignUp] = useState(false);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');

  const [formError, setFormError] = useState('');
  const { login, signup, authError } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError('');

    if (isSignUp) {
      if (password.length < 6) {
        setFormError("Password must be at least 6 characters.");
        return;
      }
      if (password !== confirmPassword) {
        setFormError("Passwords do not match.");
        return;
      }

      const success = await signup(email, password, name, 'publisher');
      if (success) navigate('/admin/dashboard');

    } else {
      const success = await login(email, password);
      if (success) navigate('/admin/dashboard');
    }
  };

  const toggleMode = () => {
    setIsSignUp(!isSignUp);
    setFormError('');
    setEmail('');
    setPassword('');
    setConfirmPassword('');
    setName('');
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-6 pattern-bg relative">

      {/* Back Button */}
