                  className="relative w-full bg-white/60 dark:bg-black/20 border border-white/50 dark:border-stone-700 text-charcoal-900 dark:text-white pl-14 pr-6 py-4 rounded-[1.5rem] focus:outline-none focus:bg-white/80 focus:border-stone-300 transition-all placeholder:text-stone-300 font-medium text-sm"
                  placeholder="Publisher Name"
                />
