            </div>
          )}

          <button
            type="submit"
            className="w-full bg-charcoal-800 dark:bg-white hover:bg-charcoal-900 dark:hover:bg-stone-200 text-cream-50 dark:text-charcoal-900 font-bold py-5 rounded-[1.5rem] transition-all shadow-lg active:scale-95 mt-4 text-sm tracking-wide uppercase flex items-center justify-center gap-2"
          >
            {isSignUp ? (
              <><UserPlus size={18} /> Create Account</>
            ) : (
              <><LogIn size={18} /> Login</>
            )}
          </button>
        </form>

        <div className="mt-8 text-center">
            <p className="text-xs text-stone-500 font-medium">
                {isSignUp ? "Already have an account?" : "Don't have an account?"}
            </p>
            <button 
                onClick={toggleMode}
                className="mt-2 text-charcoal-800 dark:text-white font-bold uppercase tracking-wide text-xs hover:underline decoration-teal-500 decoration-2 underline-offset-4"
            >
                {isSignUp ? "Login Here" : "Create Publisher Account"}
            </button>
        </div>
      </div>
    </div>
  );
};

export default AdminLogin;

