import { ShieldCheck, Lock, Mail, AlertCircle, UserPlus, LogIn, User, Music, Mic, Eye, EyeOff, Check, X } from 'lucide-react';

const Auth = () => {
  const [isSignUp, setIsSignUp] = useState(false);

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<'user' | 'publisher'>('user');

  // UX State
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [passwordError, setPasswordError] = useState('');
  const [passwordValidations, setPasswordValidations] = useState({
    length: false,
    upper: false,
    lower: false,
    number: false,
    noSpaces: true
  });

  const [formError, setFormError] = useState('');
  const { login, signup, authError } = useAuth();
  const navigate = useNavigate();

  // Reset visibility on unmount or mode toggle
  useEffect(() => {
    setShowPassword(false);
    setShowConfirmPassword(false);
  }, [isSignUp]);

  const validatePassword = (pass: string) => {
    const validations = {
      length: pass.length >= 8,
      upper: /[A-Z]/.test(pass),
      lower: /[a-z]/.test(pass),
      number: /[0-9]/.test(pass),
      noSpaces: !/\s/.test(pass)
    };
    setPasswordValidations(validations);
    return Object.values(validations).every(Boolean);
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newPass = e.target.value;
    setPassword(newPass);
    if (isSignUp) {
      validatePassword(newPass);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError('');

    if (isSignUp) {
      // Final Validation Check
      if (!validatePassword(password)) {
        setFormError("Please meet all password requirements.");
        return;
      }

      if (password !== confirmPassword) {
        setFormError("Passwords do not match.");
        return;
      }

      const success = await signup(email, password, name, role);
      if (success) navigate('/');

    } else {
      const success = await login(email, password);
      if (success) navigate('/');
    }
  };

  const toggleMode = () => {
    setIsSignUp(!isSignUp);
    setFormError('');
    setPasswordError('');
