                  <div className="flex-1">
                    <span className="text-xs font-bold text-charcoal-900 dark:text-white block mb-1">Vocals Only Verification</span>
                    <p className="text-[10px] text-stone-500 dark:text-stone-400 leading-relaxed font-medium">
                      I certify that this audio file does NOT contain any musical instruments, beats, or non-compliant background music.
                    </p>
                  </div>
                </label>
              </div>

              <button 
                type="submit" 
                className={`w-full hover:bg-charcoal-900 dark:hover:bg-stone-200 text-cream-50 dark:text-charcoal-900 font-bold py-5 rounded-[1.5rem] transition-all shadow-xl shadow-charcoal-900/10 active:scale-95 text-xs uppercase tracking-widest flex items-center justify-center gap-2 ${editingTrackId ? 'bg-gold-500 text-white' : 'bg-charcoal-800 dark:bg-white'}`}
              >
                {editingTrackId ? <><Save size={16} /> Save Changes</> : <><Upload size={16} /> Publish Content</>}
              </button>
            </form>
          </div>
        </div>

